	private static void saveScalingSettings(ScalingAlgorithm type, float scalar) {
		Properties props = loadClientSettings();
		props.setProperty("scaling_type", String.valueOf(type.ordinal()));
		props.setProperty("scaling_scalar", String.valueOf(scalar));

		saveClientSettings(props);
	}

	private static void saveClientSetting(String key, String value) {
		Properties props = loadClientSettings();
		props.setProperty(key, value);

		saveClientSettings(props);
	}

	private static void removeClientSetting(String key) {
		Properties props = loadClientSettings();
		props.remove(key);

		saveClientSettings(props);
	}

	private static Properties loadClientSettings() {
		Properties props = new Properties();
		File settings = new File("./clientSettings.conf");
		if (!settings.exists()) {
			return props;
		}
		try (FileInputStream in = new FileInputStream("./clientSettings.conf")) {
			props.load(in);
		} catch (IOException e) {
			System.out.println("Error loading client settings.");
			e.printStackTrace();
		}
		return props;
	}

	private static void saveClientSettings(Properties props) {
		try (FileOutputStream out = new FileOutputStream("./clientSettings.conf")) {
			props.store(out, "Client settings");
		} catch (IOException e) {
			System.out.println("Something went wrong saving client settings");
			e.printStackTrace();
		}
	}

	private static void loadVoidscapeClientSettings() {
		Properties props = loadClientSettings();
		String chatOverlay = props.getProperty(CLIENT_SETTING_CHAT_OVERLAY);
		if (chatOverlay != null && !chatOverlay.trim().isEmpty()) {
			C_CHAT_OVERLAY = Boolean.parseBoolean(chatOverlay);
		}
		String pendingInputMarker = props.getProperty(CLIENT_SETTING_PENDING_INPUT_MARKER);
		if (pendingInputMarker != null && !pendingInputMarker.trim().isEmpty()) {
			optionPendingInputMarker = Boolean.parseBoolean(pendingInputMarker);
		}
		String cameraInterpolation = props.getProperty(CLIENT_SETTING_CAMERA_INTERPOLATION);
		if (cameraInterpolation != null && !cameraInterpolation.trim().isEmpty()) {
			optionCameraInterpolation = Boolean.parseBoolean(cameraInterpolation);
		}
	}

	private static void saveChatOverlaySetting() {
		saveClientSetting(CLIENT_SETTING_CHAT_OVERLAY, Boolean.toString(C_CHAT_OVERLAY));
	}

	private static void savePendingInputMarkerSetting() {
		saveClientSetting(CLIENT_SETTING_PENDING_INPUT_MARKER, Boolean.toString(optionPendingInputMarker));
	}

	private static void saveCameraInterpolationSetting() {
		saveClientSetting(CLIENT_SETTING_CAMERA_INTERPOLATION, Boolean.toString(optionCameraInterpolation));
	}

	private static boolean isValidEmailAddress(String email) {
		boolean stricterFilter = true;
		String stricterFilterString = "[A-Z0-9a-z._%+-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,4}";
		String laxString = ".+@.+\\.[A-Za-z]{2}[A-Za-z]*";
		String emailRegex = stricterFilter ? stricterFilterString : laxString;
		java.util.regex.Pattern p = java.util.regex.Pattern.compile(emailRegex);
		java.util.regex.Matcher m = p.matcher(email);
		return m.matches();
	}

	public static String formatStackAmount(int length) {
		if (length < 100000) {
			return String.valueOf(length);
		}
		if (length < 10000000) {
			return "@whi@" + length / 1000 + "K";
		}
		return "@gre@" + length / 1000000 + "M";
	}

