	public final void addMouseClick(int button, int x, int y) {
		try {

			this.mouseClickX[this.mouseClickCount] = x;
			this.mouseClickY[this.mouseClickCount] = y;
			this.mouseClickCount = this.mouseClickCount + 1 & 8191;
			for (int i = 10; i < 4000; ++i) {
				int pID = 8191 & this.mouseClickCount - i;
				if (this.mouseClickX[pID] == x && y == this.mouseClickY[pID]) {
					boolean hasInteracted = false;

					for (int j = 1; j < i; ++j) {
						int sID = this.mouseClickCount - j & 8191;
						int psID = 8191 & pID - j;
						if (x != this.mouseClickX[psID] || y != this.mouseClickY[psID]) {
							hasInteracted = true;
						}

						if (this.mouseClickX[sID] != this.mouseClickX[psID]
							|| this.mouseClickY[sID] != this.mouseClickY[psID]) {
							break;
						}

						if (j == i - 1 && hasInteracted && this.combatTimeout == 0 && this.logoutTimeout == 0) {
							this.sendLogout(0);
							return;
						}
					}
				}
			}

		} catch (RuntimeException var11) {
			throw GenUtil.makeThrowable(var11, "client.Q(" + x + ',' + "dummy" + ',' + button + ',' + y + ')');
		}
	}

	private boolean isInsideVoidArenaLobby(int worldX, int worldY) {
		return worldX >= 582 && worldX <= 616 && worldY >= 2910 && worldY <= 2916;
	}

	private boolean isInsideVoidArena(int worldX, int worldY) {
		return isInsideVoidArenaLobby(worldX, worldY)
			|| worldX >= 584 && worldX <= 590 && worldY >= 2897 && worldY <= 2909
			|| worldX >= 592 && worldX <= 598 && worldY >= 2897 && worldY <= 2909
			|| worldX >= 600 && worldX <= 606 && worldY >= 2897 && worldY <= 2909
			|| worldX >= 608 && worldX <= 614 && worldY >= 2897 && worldY <= 2909;
	}

	private boolean isInsideUndeadSiegeArena(int worldX, int worldY) {
		return worldX >= 579 && worldX <= 621 && worldY >= 99 && worldY <= 141;
	}

	private boolean shouldUseVoidWorldReskin(int worldX, int worldY) {
		if (Config.C_WORLD_RESKIN_MODE == Config.WORLD_RESKIN_VOID) {
			return true;
		}
		if (Config.C_WORLD_RESKIN_MODE == Config.WORLD_RESKIN_AUTHENTIC) {
			return false;
		}
		return isInsideUndeadSiegeArena(worldX, worldY);
	}

	private void applyWorldReskinForRegion(int worldX, int worldY) {
		if (this.world == null) {
			return;
		}
		this.world.setVoidReskinEnabled(shouldUseVoidWorldReskin(worldX, worldY));
	}

	private boolean isLocalPlayerInsideVoidArenaLobby() {
		return isInsideVoidArenaLobby(this.playerLocalX + this.midRegionBaseX, this.playerLocalZ + this.midRegionBaseZ);
	}

	private boolean isLocalPlayerInsideVoidArena() {
		return isInsideVoidArena(this.playerLocalX + this.midRegionBaseX, this.playerLocalZ + this.midRegionBaseZ);
	}

