	private int normalizeVoidscapeHairColour(int colour) {
		if (colour < VOIDSCAPE_HAIR_COLOUR_MIN || colour > VOIDSCAPE_HAIR_COLOUR_MAX) {
			return VOIDSCAPE_HAIR_COLOUR_MIN;
		}
		return colour;
	}

