	private void drawVoidArenaCountdownOverlay() {
		if (this.voidArenaCountdownEndMillis <= 0L) {
			return;
		}
		long now = System.currentTimeMillis();
		long remaining = this.voidArenaCountdownEndMillis - now;
		boolean showStart = remaining <= 0L && now <= this.voidArenaCountdownEndMillis + 1000L;
		if (remaining <= 0L && !showStart) {
			this.voidArenaCountdownEndMillis = 0L;
			return;
		}
		String text = showStart ? "START!" : String.valueOf(Math.max(1L, (remaining + 999L) / 1000L));
		int boxW = showStart ? 142 : 92;
		int boxH = 54;
		int x = this.halfGameWidth() - boxW / 2;
		int y = this.halfGameHeight() - boxH / 2 - 22;
		this.getSurface().drawBoxAlpha(x, y, boxW, boxH, UiSkin.VOID_BODY, 185);
		this.getSurface().drawBoxBorder(x, boxW, y, boxH, UiSkin.GOLD_LINE);
		this.getSurface().drawBoxBorder(x + 2, boxW - 4, y + 2, boxH - 4, UiSkin.PURPLE_EDGE);
		this.getSurface().drawColoredStringCentered(this.halfGameWidth(), text,
			showStart ? UiSkin.GOOD : UiSkin.GOLD_HOT, 0, 5, y + 36);
	}

	private void drawDialogLogout() {
		try {

			// Paint geometry: derived once, shared by both skins (no hit rects here).
			int dialogWidth = 260;
			int dialogHeight = 60;
			int dialogX = UiAnchor.centeredDialogX(getGameWidth(), dialogWidth);
			int dialogY = (getGameHeight() - dialogHeight) / 2;
			if (useVoidscapeHudSkin()) {
				UiSkin.modal(this.getSurface(), dialogX, dialogY, dialogWidth, dialogHeight, null);
				this.getSurface().drawColoredStringCentered(dialogX + dialogWidth / 2, "Logging out...", UiSkin.GOLD_TITLE, 0, 5, dialogY + 36);
			} else {
				this.getSurface().drawBox(dialogX, dialogY, dialogWidth, dialogHeight, 0);
				this.getSurface().drawBoxBorder(dialogX, dialogWidth, dialogY, dialogHeight, 0xFFFFFF);
				// dialogX + dialogWidth / 2 == (getGameWidth() - 256) / 2 + 256 / 2 at every width.
				this.getSurface().drawColoredStringCentered(dialogX + dialogWidth / 2, "Logging out...", 0xFFFFFF, 0, 5, dialogY + 36);
			}
		} catch (RuntimeException var3) {
			throw GenUtil.makeThrowable(var3, "client.SD(" + "dummy" + ')');
		}
	}

	private void drawDialogOptionsMenu(int var1) {
		try {

			if (isVoidscapeWelcomeMenu()) {
				drawVoidscapeWelcomeMenu();
				return;
			}
			if (isVoidscapePathMenu()) {
				drawVoidscapePathMenu();
				return;
			}
			if (isVoidscapeTitleMenu()) {
				drawVoidscapeTitleMenu();
				return;
			}

			if (isAndroid()) {
				int startY = 25;
				int startX = 5;
				int spread = 20;
				if (voidscapeUseMobileMenuAboveChat()) {
					startY = voidscapeMobileOptionMenuBaselineY(this.optionsMenuCount, spread);
				}
				int highest = 0;
				int boxEndY = 0;
				for (int j = 0; j < optionsMenuCount; j++) {
					int textWidth = getSurface().stringWidth(6, optionsMenuText[j]) + 15;
					if (highest < textWidth) {
						highest = textWidth;
					}
					if (boxEndY < startY + j * spread + 20) {
						boxEndY = startY + j * spread + 20;
					}
				}
				if (mouseButtonClick != 0) {
					boolean nullOption = true;
					for (int i = 0; i < optionsMenuCount; i++) {
						if (mouseX > startX && mouseX < startX + highest && mouseY > startY + i * spread - 15
							&& mouseY < startY + i * spread) {
							this.packetHandler.getClientStream().newPacket(116);
							this.packetHandler.getClientStream().bufferBits.putByte(i);
							this.packetHandler.getClientStream().finishPacket();
							nullOption = false;
							break;
						}
					}
					if (nullOption) {
						this.packetHandler.getClientStream().newPacket(116);
						this.packetHandler.getClientStream().bufferBits.putByte(-1);
						this.packetHandler.getClientStream().finishPacket();
					}
					mouseButtonClick = 0;
					optionsMenuShow = false;
					return;
				}
				for (int j = 0; j < optionsMenuCount; j++) {
					int k = 65535;
					if (mouseX > startX && mouseX < startX + highest && mouseY > startY + j * spread - 15
						&& mouseY < startY + j * spread)
						k = 0xff0000;

					this.getSurface().drawString(
						(S_WANT_KEYBOARD_SHORTCUTS > 1 ? "(" + (j + 1) + ")" : "") + optionsMenuText[j],
						startX + 10, startY + j * spread, k, 6);
				}
			} else {
				int var2;
				int startY = 0;
				int startX = 6;
				int rowHeight = 12;
				if (C_CUSTOM_UI) {
					if (useVoidscapeHudSkin()) {
						startY = Math.max(8, voidscapeChatFrameTop() - this.optionsMenuCount * rowHeight - 10);
					} else {
						startY = getGameHeight() - 100;
					}
				}
				int shortcutWidth = S_WANT_KEYBOARD_SHORTCUTS > 1 ? 24 : 9;
				if (this.mouseButtonClick == 0) {
					// Draw
					var2 = 0;
					while (this.optionsMenuCount > var2) {
						int var3 = '\uffff';
						if (this.mouseX >= startX && this.mouseX < startX + this.getSurface().stringWidth(1, this.optionsMenuText[var2])
							+ shortcutWidth
							&& this.mouseY > startY + 2 + var2 * rowHeight && this.mouseY < startY + 2 + var2 * rowHeight + rowHeight) {
							var3 = 0xFF0000;
						}

						this.getSurface().drawString(
							(S_WANT_KEYBOARD_SHORTCUTS > 1 ? "(" + (var2 + 1) + ") " : "") + this.optionsMenuText[var2],
							startX, var2 * rowHeight + 12 + startY, var3, 1);
						++var2;
					}
				} else {
					// Click
					boolean nullOption = true;
					for (var2 = 0; var2 < this.optionsMenuCount; ++var2) {
						if (this.mouseX >= startX && this.mouseX < startX + this.getSurface().stringWidth(1, this.optionsMenuText[var2])
							+ shortcutWidth
							&& startY + 2 + var2 * rowHeight < this.mouseY && startY + 2 + rowHeight + var2 * rowHeight > this.mouseY) {
							this.packetHandler.getClientStream().newPacket(116);
							this.packetHandler.getClientStream().bufferBits.putByte(var2);
							this.packetHandler.getClientStream().finishPacket();
							nullOption = false;
							break;
						}
					}

					if (nullOption) {
						this.packetHandler.getClientStream().newPacket(116);
						this.packetHandler.getClientStream().bufferBits.putByte(-1);
						this.packetHandler.getClientStream().finishPacket();
					}
					this.optionsMenuShow = false;
					this.mouseButtonClick = 0;
				}
			}
		} catch (RuntimeException var4) {
			throw GenUtil.makeThrowable(var4, "client.FB(" + var1 + ')');
		}
	}

	private boolean isVoidscapePathMenu() {
		return this.useVoidscapeLogin()
			&& this.optionsMenuCount == 3
			&& this.optionsMenuText[0] != null
			&& this.optionsMenuText[1] != null
			&& this.optionsMenuText[2] != null
			&& this.optionsMenuText[0].startsWith("Warrior's Path - 2x XP:")
			&& this.optionsMenuText[1].startsWith("Forager's Path - 2x XP:")
			&& this.optionsMenuText[2].startsWith("Arcanist's Path - 2x XP:");
	}

	// Contract: option prefixes come from server VoidOnboarding.OPTION_* constants.
	private boolean isVoidscapeWelcomeMenu() {
		return this.useVoidscapeLogin()
			&& this.optionsMenuCount == 2
			&& this.optionsMenuText[0] != null
			&& this.optionsMenuText[1] != null
			&& this.optionsMenuText[0].startsWith("I've played Classic")
			&& this.optionsMenuText[1].startsWith("Skip the intro");
	}

	private boolean isVoidscapeTitleMenu() {
		return isVoidscapeTitleHubMenu() || isVoidscapeTitleCatalogMenu() || isVoidscapeTitleDetailMenu();
	}

	private boolean isVoidscapeTitleHubMenu() {
		if (this.optionsMenuCount < 6 || this.optionsMenuText[0] == null) {
			return false;
		}
		if (!this.optionsMenuText[0].startsWith("Active title:") && !this.optionsMenuText[0].startsWith("Active:")) {
			return false;
		}
		return titleMenuOptionIndexStartsWith("Unlocked titles") >= 0
			&& titleMenuOptionIndexStartsWith("All titles") >= 0
			&& titleMenuOptionIndexStartsWith("Unique titles") >= 0
			&& titleMenuOptionIndexStartsWith("Renown titles") >= 0
			&& titleMenuOptionIndexStartsWith("Feat titles") >= 0;
	}

	private boolean isVoidscapeTitleCatalogMenu() {
		return this.optionsMenuCount >= 4
			&& this.optionsMenuText[0] != null
			&& isVoidscapeTitleCatalogHeader(this.optionsMenuText[0]);
	}

	private boolean isVoidscapeTitleDetailMenu() {
		return this.optionsMenuCount >= 6
			&& this.optionsMenuText[0] != null
			&& this.optionsMenuText[0].startsWith("Title details: ");
	}

	private boolean isVoidscapeTitleCatalogHeader(String text) {
		return text.startsWith("All titles - page ")
			|| text.startsWith("Unlocked titles - page ")
			|| text.startsWith("Unique titles - page ")
			|| text.startsWith("Renown titles - page ")
			|| text.startsWith("Feat titles - page ");
	}

	private void drawVoidscapeTitleMenu() {
		this.showUiTab = 0;
		if (isVoidscapeTitleDetailMenu()) {
			drawVoidscapeTitleDetailMenu();
		} else if (isVoidscapeTitleCatalogMenu()) {
			drawVoidscapeTitleCatalogMenu();
		} else {
			drawVoidscapeTitleHubMenu();
		}
	}

	private void drawVoidscapeTitleHubMenu() {
		int panelWidth = Math.min(420, this.getGameWidth() - 20);
		int panelHeight = Math.min(244, this.getGameHeight() - 24);
		int panelX = (this.getGameWidth() - panelWidth) / 2;
		int panelY = (this.getGameHeight() - panelHeight) / 2;
		int cx = panelX + panelWidth / 2;

		drawVoidscapeTitleFrame(panelX, panelY, panelWidth, panelHeight);
		drawVoidscapeCenteredText(cx, "Voidscape Titles", 0xffff00, 4, panelY + 24);
		drawVoidscapeCenteredText(cx, titleHubActiveText(), 0xffffff, 1, panelY + 45);

		int buttonW = (panelWidth - 48) / 2;
		int buttonH = 25;
		int firstX = panelX + 18;
		int secondX = firstX + buttonW + 12;
		int rowY = panelY + 64;
		for (int i = 1; i < this.optionsMenuCount; i++) {
			int column = (i - 1) % 2;
			int row = (i - 1) / 2;
			int x = column == 0 ? firstX : secondX;
			int y = rowY + row * 31;
			String option = this.optionsMenuText[i] == null ? "" : this.optionsMenuText[i];
			if (drawVoidscapeTitleButton(x, y, buttonW, buttonH, option, i, option.startsWith("Close"))) {
				return;
			}
		}

		handleVoidscapeTitlePanelMiss(panelX, panelY, panelWidth, panelHeight);
	}

	private void drawVoidscapeTitleCatalogMenu() {
		int panelWidth = Math.min(isAndroid() ? 560 : 520, this.getGameWidth() - 16);
		int panelHeight = Math.min(isAndroid() ? 350 : 306, this.getGameHeight() - 24);
		int panelX = (this.getGameWidth() - panelWidth) / 2;
		int panelY = (this.getGameHeight() - panelHeight) / 2;
		int cx = panelX + panelWidth / 2;
		String header = this.optionsMenuText[0];
		String currentCategory = titleCatalogCommandFromHeader(header);

		drawVoidscapeTitleFrame(panelX, panelY, panelWidth, panelHeight);
		this.getSurface().drawBoxAlpha(panelX + 2, panelY + 2, panelWidth - 4, 22, UiSkin.VITAL_PRAYER, 222);
		this.getSurface().drawLineHoriz(panelX + 3, panelY + 24, panelWidth - 6, UiSkin.GOLD_LINE);
		drawVoidscapeCenteredText(cx, "Achievement Titles", UiSkin.GOLD_TITLE, UiSkin.FONT_TITLE, panelY + 17);
		drawVoidscapeCenteredText(cx, titleCatalogSummaryText(header), UiSkin.TEXT_BODY, UiSkin.FONT_SMALL, panelY + 38);

		int tabY = panelY + 45;
		int tabH = voidscapeTitleTabHeight();
		int tabX = panelX + 10;
		int tabW = (panelWidth - 20) / 5;
		if (drawVoidscapeTitleTab(tabX, tabY, tabW - 3, "All", titleMenuOptionIndexStartsWith("View all titles"), "all".equals(currentCategory))) return;
		if (drawVoidscapeTitleTab(tabX + tabW, tabY, tabW - 3, "Unlocked", titleMenuOptionIndexStartsWith("View unlocked titles"), "unlocked".equals(currentCategory))) return;
		if (drawVoidscapeTitleTab(tabX + tabW * 2, tabY, tabW - 3, "Renown", titleMenuOptionIndexStartsWith("View renown titles"), "renown".equals(currentCategory))) return;
		if (drawVoidscapeTitleTab(tabX + tabW * 3, tabY, tabW - 3, "Feat", titleMenuOptionIndexStartsWith("View feat titles"), "feat".equals(currentCategory))) return;
		if (drawVoidscapeTitleTab(tabX + tabW * 4, tabY, tabW - 3, "Unique", titleMenuOptionIndexStartsWith("View unique titles"), "unique".equals(currentCategory))) return;

		int tableX = panelX + 12;
		int tableW = panelWidth - 24;
		int tierW = isAndroid() ? 78 : 70;
		int holderW = isAndroid() ? 94 : 88;
		int ageW = isAndroid() ? 58 : 52;
		int titleW = Math.max(132, tableW - tierW - holderW - ageW);
		int headerY = tabY + tabH + 16;
		this.getSurface().drawBoxAlpha(tableX, headerY - 12, tableW, 16, UiSkin.VOID_HEADER, 220);
		this.getSurface().drawLineHoriz(tableX, headerY + 4, tableW, UiSkin.GOLD_LINE);
		this.getSurface().drawString("Achievement", tableX + 6, headerY, UiSkin.GOLD_HEADER, UiSkin.FONT_SMALL);
		this.getSurface().drawColoredStringCentered(tableX + titleW + tierW / 2, "Tier", UiSkin.GOLD_HEADER, 0, UiSkin.FONT_SMALL, headerY);
		this.getSurface().drawString("Player", tableX + titleW + tierW + 6, headerY, UiSkin.GOLD_HEADER, UiSkin.FONT_SMALL);
		this.getSurface().drawString("Age", tableX + titleW + tierW + holderW + 4, headerY, UiSkin.GOLD_HEADER, UiSkin.FONT_SMALL);

		int rowY = headerY + 8;
		int rowH = isAndroid() ? 23 : 17;
		int firstRow = -1;
		int lastRow = -1;
		for (int i = 1; i < this.optionsMenuCount; i++) {
			String option = this.optionsMenuText[i] == null ? "" : this.optionsMenuText[i];
			if (isVoidscapeTitleNavigationOption(option)) {
				continue;
			}
			if (firstRow < 0) firstRow = i;
			lastRow = i;
			if (drawVoidscapeTitleRow(tableX, rowY, tableW, rowH, option, i, titleW, tierW, holderW, ageW)) {
				return;
			}
				rowY += rowH;
			}

			int navY = panelY + panelHeight - 29;
			int pageY = navY - 8;
			int prev = titleMenuOptionIndexStartsWith("< Previous page");
			int next = titleMenuOptionIndexStartsWith("Next page");
			int change = titleMenuOptionIndexStartsWith("Change category");
			int close = titleMenuOptionIndexStartsWith("Close");
			if (firstRow >= 0) {
				String pageText = titleCatalogPageText(header, firstRow, lastRow);
				this.getSurface().drawColoredStringCentered(cx, pageText, UiSkin.TEXT_DIM, 0, UiSkin.FONT_SMALL, pageY);
			}
			int buttonW = isAndroid() ? 104 : 82;
			int x = panelX + 14;
			if (prev >= 0 && drawVoidscapeTitleButton(x, navY, buttonW, 22, "Previous", prev, false)) return;
			x += buttonW + 7;
			if (next >= 0 && drawVoidscapeTitleButton(x, navY, buttonW, 22, "Next", next, false)) return;
			if (change >= 0 && drawVoidscapeTitleButton(cx - 51, navY, 102, 22, "Categories", change, false)) return;
			if (close >= 0 && drawVoidscapeTitleButton(panelX + panelWidth - 86, navY, 72, 22, "Close", close, true)) return;

			handleVoidscapeTitlePanelMiss(panelX, panelY, panelWidth, panelHeight);
		}

	private void drawVoidscapeTitleDetailMenu() {
		int panelWidth = Math.min(438, this.getGameWidth() - 16);
		int panelHeight = Math.min(246, this.getGameHeight() - 24);
		int panelX = (this.getGameWidth() - panelWidth) / 2;
		int panelY = (this.getGameHeight() - panelHeight) / 2;
		int cx = panelX + panelWidth / 2;
		String title = this.optionsMenuText[0].substring("Title details: ".length());

		drawVoidscapeTitleFrame(panelX, panelY, panelWidth, panelHeight);
		drawVoidscapeCenteredText(cx, "Title Details", 0xffff00, 4, panelY + 24);
		drawVoidscapeCenteredText(cx, title, 0xff3030, 1, panelY + 44);

		int lineY = panelY + 68;
		for (int i = 1; i < this.optionsMenuCount; i++) {
			String option = this.optionsMenuText[i] == null ? "" : this.optionsMenuText[i];
			if (isVoidscapeTitleDetailActionOption(option)) {
				continue;
			}
			this.getSurface().drawString(option, panelX + 18, lineY, titleDetailLineColor(option), 1);
			lineY += 18;
		}

		int equip = titleMenuOptionIndexStartsWith("Equip title");
		int back = titleMenuOptionIndexStartsWith("Back to ");
		int close = titleMenuOptionIndexStartsWith("Close");
		int buttonY = panelY + panelHeight - 34;
		if (equip >= 0) {
			int equipX = panelX + 18;
			if (drawVoidscapeTitleButton(equipX, buttonY, 112, 22, "Equip", equip, false)) return;
			if (back >= 0 && drawVoidscapeTitleButton(equipX + 124, buttonY, 112, 22, "Back", back, false)) return;
			if (close >= 0 && drawVoidscapeTitleButton(panelX + panelWidth - 86, buttonY, 70, 22, "Close", close, true)) return;
		} else {
			if (back >= 0 && drawVoidscapeTitleButton(panelX + 18, buttonY, 112, 22, "Back", back, false)) return;
			if (close >= 0 && drawVoidscapeTitleButton(panelX + panelWidth - 86, buttonY, 70, 22, "Close", close, true)) return;
		}

		handleVoidscapeTitlePanelMiss(panelX, panelY, panelWidth, panelHeight);
	}

	private void drawVoidscapeTitleFrame(int x, int y, int width, int height) {
		this.getSurface().drawBoxAlpha(0, 0, this.getGameWidth(), this.getGameHeight(), 0, 118);
		UiSkin.glassPanel(this.getSurface(), x, y, width, height, UiSkin.A_GLASS_TEXT);
		this.getSurface().drawLineHoriz(x + 8, y + 7, width - 16, UiSkin.GOLD_LINE);
		this.getSurface().drawLineHoriz(x + 8, y + height - 8, width - 16, UiSkin.SHADOW_B);
	}

	private boolean drawVoidscapeTitleButton(int x, int y, int width, int height, String label, int option, boolean close) {
		boolean hover = this.mouseX >= x && this.mouseX <= x + width && this.mouseY >= y && this.mouseY <= y + height;
		int fill = hover ? UiSkin.PURPLE_SELECT : UiSkin.VOID_BOX;
		int border = hover ? UiSkin.GOLD_HOT : UiSkin.GOLD_LINE;
		this.getSurface().drawBoxAlpha(x, y, width, height, fill, 235);
		this.getSurface().drawBoxBorder(x, width, y, height, border);
		this.getSurface().drawColoredStringCentered(x + width / 2, label, close ? UiSkin.DANGER_GLYPH : UiSkin.TEXT_BODY, 0, UiSkin.FONT_BODY, y + height / 2 + 4);
		if (hover && this.mouseButtonClick == 1) {
			sendOptionsMenuChoice(option);
			return true;
		}
		return false;
	}

		private int voidscapeTitleTabHeight() {
			return isAndroid() ? 24 : 19;
		}

		private boolean drawVoidscapeTitleTab(int x, int y, int width, String label, int option, boolean selected) {
			int height = voidscapeTitleTabHeight();
			boolean hover = this.mouseX >= x && this.mouseX <= x + width && this.mouseY >= y && this.mouseY <= y + height;
			int fill = selected ? UiSkin.VITAL_PRAYER : hover ? UiSkin.VOID_LINE : UiSkin.VOID_BOX;
			int border = selected ? UiSkin.GOLD_HOT : hover ? UiSkin.GOLD_HOT : UiSkin.GOLD_LINE;
			int font = isAndroid() ? UiSkin.FONT_BODY : UiSkin.FONT_SMALL;
			this.getSurface().drawBoxAlpha(x, y, width, height, fill, selected ? 232 : 218);
			this.getSurface().drawBoxBorder(x, width, y, height, border);
			this.getSurface().drawColoredStringCentered(x + width / 2, label, selected ? UiSkin.GOLD_TITLE : UiSkin.TEXT_BODY, 0, font, y + height / 2 + 4);
			if (hover && !selected && option >= 0 && this.mouseButtonClick == 1) {
				sendOptionsMenuChoice(option);
				return true;
		}
		return false;
	}

	private boolean drawVoidscapeTitleRow(int x, int y, int width, int height, String label, int option,
										 int titleW, int tierW, int holderW, int ageW) {
		String[] cells = parseVoidscapeTitleCells(label);
		boolean structured = cells != null;
			boolean disabled = label.startsWith("No titles in this category");
			boolean active = structured ? "1".equals(cells[7]) : label.startsWith("* ");
			boolean hover = !disabled && this.mouseX >= x && this.mouseX <= x + width && this.mouseY >= y && this.mouseY <= y + height;
			int fill = active ? UiSkin.PURPLE_SELECT : hover ? UiSkin.PURPLE_SELECT : option % 2 == 0 ? UiSkin.VOID_BOX : UiSkin.VOID_BODY;
			int border = active ? UiSkin.GOLD_LINE : hover ? UiSkin.GOLD_HOT : UiSkin.VOID_LINE;
			this.getSurface().drawBoxAlpha(x, y, width, height, fill, active ? 190 : hover ? 116 : 158);
			this.getSurface().drawLineHoriz(x, y + height - 1, width, border);
			if (active || hover) {
				this.getSurface().drawBoxBorder(x, width, y, height, border);
			}
			if (structured) {
				int textY = y + height / 2 + 4;
				int tierX = x + titleW;
				int holderX = tierX + tierW;
				int ageX = holderX + holderW;
				int titleColor = active ? UiSkin.GOLD_TITLE : "locked".equals(cells[6]) || "held".equals(cells[6]) ? UiSkin.TEXT_DIM : UiSkin.TEXT_BODY;
				this.getSurface().drawString(fitVoidscapeText(cells[0], titleW - 10, UiSkin.FONT_BODY), x + 6, textY, titleColor, UiSkin.FONT_BODY);
				drawVoidscapeTitleTierPill(tierX + 5, y + 2, tierW - 10, height - 4, cells[1], parseTitleInt(cells[2]), "1".equals(cells[3]));
				int holderColor = "Open".equals(cells[4]) ? UiSkin.GOLD_HOT : "-".equals(cells[4]) ? UiSkin.TEXT_DIM : UiSkin.GOOD;
				this.getSurface().drawString(fitVoidscapeText(cells[4], holderW - 10, UiSkin.FONT_SMALL), holderX + 6, textY,
					holderColor, UiSkin.FONT_SMALL);
				this.getSurface().drawString(fitVoidscapeText(cells[5], ageW - 8, UiSkin.FONT_SMALL), ageX + 4, textY, UiSkin.TEXT_LABEL, UiSkin.FONT_SMALL);
			} else {
				this.getSurface().drawString(titleRowDisplayText(label), x + 6, y + 13, disabled ? UiSkin.TEXT_DIM : UiSkin.TEXT_BODY, UiSkin.FONT_BODY);
		}
		if (hover && this.mouseButtonClick == 1) {
			sendOptionsMenuChoice(option);
			return true;
		}
		return false;
		}

		private void drawVoidscapeTitleTierPill(int x, int y, int width, int height, String label, int tier, boolean record) {
			int fill = record ? UiSkin.GOLD_LINE : tier == 2 ? UiSkin.GOLD_LINE : tier == 1 ? UiSkin.PURPLE_SELECT : UiSkin.VITAL_META;
			int border = record ? UiSkin.GOLD_HOT : tier == 2 ? UiSkin.GOLD_HOT : tier == 1 ? UiSkin.PURPLE_FOCUS : UiSkin.FIELD_BORDER_IDLE;
			int text = record || tier == 0 ? UiSkin.VOID_BODY : UiSkin.GOLD_TITLE;
			this.getSurface().drawBoxAlpha(x, y, width, height, fill, record ? 235 : 220);
			this.getSurface().drawBoxBorder(x, width, y, height, border);
			this.getSurface().drawColoredStringCentered(x + width / 2, fitVoidscapeText(label, width - 6, UiSkin.FONT_SMALL),
				text, 0, UiSkin.FONT_SMALL, y + height / 2 + 4);
		}

	private String[] parseVoidscapeTitleCells(String label) {
		int marker = label == null ? -1 : label.indexOf("~vstitle~");
		if (marker < 0) {
			return null;
		}
		String[] cells = label.substring(marker + "~vstitle~".length()).split("\\|", -1);
		return cells.length >= 8 ? cells : null;
	}

	private String titleRowDisplayText(String label) {
		int marker = label == null ? -1 : label.indexOf("~vstitle~");
		return marker < 0 ? label : label.substring(0, marker).trim();
	}

		private int parseTitleInt(String value) {
			try {
				return Integer.parseInt(value);
			} catch (NumberFormatException ex) {
				return 0;
			}
		}

		private String titleCatalogSummaryText(String header) {
			if (header == null) {
				return "";
			}
			int showingStart = header.indexOf(" - showing ");
			int unlockedStart = header.indexOf(" - unlocked ");
			if (showingStart >= 0 && unlockedStart > showingStart) {
				return header.substring(0, showingStart) + header.substring(unlockedStart);
			}
			return header;
		}

		private String titleCatalogPageText(String header, int firstRow, int lastRow) {
			int pageStart = header == null ? -1 : header.indexOf("page ");
			String page = pageStart < 0 ? "" : header.substring(pageStart).split(" - ")[0];
		int showingStart = header == null ? -1 : header.indexOf("showing ");
		if (showingStart >= 0) {
			String showing = header.substring(showingStart + "showing ".length()).split(" - ")[0];
			return page + " (" + showing + ")";
		}
		return page;
	}

	private void handleVoidscapeTitlePanelMiss(int panelX, int panelY, int panelWidth, int panelHeight) {
		if (this.mouseButtonClick != 1) {
			return;
		}
		boolean inside = this.mouseX >= panelX && this.mouseX <= panelX + panelWidth
			&& this.mouseY >= panelY && this.mouseY <= panelY + panelHeight;
		if (!inside) {
			sendOptionsMenuChoice(-1);
		} else {
			this.mouseButtonClick = 0;
		}
	}

	private boolean isVoidscapeTitleNavigationOption(String option) {
		return option.startsWith("< Previous page")
			|| option.startsWith("Next page")
			|| option.startsWith("View all titles")
			|| option.startsWith("View unlocked titles")
			|| option.startsWith("View unique titles")
			|| option.startsWith("View renown titles")
			|| option.startsWith("View feat titles")
			|| option.startsWith("Change category")
			|| option.startsWith("Close");
	}

	private boolean isVoidscapeTitleDetailActionOption(String option) {
		return option.startsWith("Equip title")
			|| option.startsWith("Back to ")
			|| option.startsWith("Close");
	}

	private int titleDetailLineColor(String option) {
		if (option.startsWith("Progress:")) {
			return 0xd9b6ff;
		}
		if (option.startsWith("Tier: @yel@unique")) {
			return 0xff8080;
		}
		if (option.startsWith("Tier: @mag@feat")) {
			return 0xd9b6ff;
		}
		if (option.startsWith("Tier: @whi@renown")) {
			return 0x80d8ff;
		}
		if (option.startsWith("Lifecycle: first") || option.startsWith("Lifecycle: contested") || option.startsWith("Lifecycle: item-bound")
			|| option.startsWith("Claim:") || option.startsWith("Holder:")) {
			return 0xffe080;
		}
		if (option.startsWith("Lifecycle: reusable")) {
			return 0x80d8ff;
		}
		if (option.endsWith("active") || option.endsWith("unlocked")) {
			return 0x80ff80;
		}
		if (option.indexOf("locked") >= 0) {
			return 0xff8080;
		}
		return 0xffffff;
	}

	private String titleHubActiveText() {
		String text = this.optionsMenuText[0] == null ? "Active title: none" : this.optionsMenuText[0];
		if (text.startsWith("Active:")) {
			return "Active title: " + text.substring("Active:".length()).trim();
		}
		return text;
	}

	private String titleCatalogCommandFromHeader(String header) {
		if (header.startsWith("Unlocked titles")) return "unlocked";
		if (header.startsWith("Unique titles")) return "unique";
		if (header.startsWith("Renown titles")) return "renown";
		if (header.startsWith("Feat titles")) return "feat";
		return "all";
	}

	private int titleMenuOptionIndexStartsWith(String prefix) {
		for (int i = 0; i < this.optionsMenuCount; i++) {
			if (this.optionsMenuText[i] != null && this.optionsMenuText[i].startsWith(prefix)) {
				return i;
			}
		}
		return -1;
	}

