	private void drawWorldWalkSceneRoute() {
		if (isVoidRushUiLocked() || !this.worldWalkRouteOk || !this.worldMapPanel.isSceneRouteVisible()) return;
		if (this.worldWalkRouteX == null || this.worldWalkRouteY == null) return;
		final int count = Math.min(this.worldWalkRouteX.length, this.worldWalkRouteY.length);
		if (count == 0) return;

		final int currentFloor = (this.playerLocalZ + this.midRegionBaseZ) / 944;
		final int routeColor = 0x40FF40;
		for (int i = 0; i < count; i++) {
			final int worldX = this.worldWalkRouteX[i];
			final int worldY = this.worldWalkRouteY[i];
			if (worldY / 944 != currentFloor) continue;

			final int localX = worldX - this.midRegionBaseX;
			final int localZ = worldY - this.midRegionBaseZ;
			if (localX < 0 || localZ < 0 || localX >= 95 || localZ >= 95) continue;

			final int x0 = localX * this.tileSize;
			final int z0 = localZ * this.tileSize;
			final int x1 = x0 + this.tileSize;
			final int z1 = z0 + this.tileSize;
			if (!projectWorldWalkTileCorner(0, x0, z0)) continue;
			if (!projectWorldWalkTileCorner(1, x1, z0)) continue;
			if (!projectWorldWalkTileCorner(2, x1, z1)) continue;
			if (!projectWorldWalkTileCorner(3, x0, z1)) continue;

			final int[] p0 = this.worldWalkSceneTileProjection[0];
			final int[] p1 = this.worldWalkSceneTileProjection[1];
			final int[] p2 = this.worldWalkSceneTileProjection[2];
			final int[] p3 = this.worldWalkSceneTileProjection[3];
			this.getSurface().drawQuadrilateralAlpha(p0[0], p0[1], p1[0], p1[1], p2[0], p2[1],
				p3[0], p3[1], routeColor, 80);
			this.getSurface().drawLineAlpha(p0[0], p0[1], p1[0], p1[1], routeColor, 150);
			this.getSurface().drawLineAlpha(p1[0], p1[1], p2[0], p2[1], routeColor, 150);
			this.getSurface().drawLineAlpha(p2[0], p2[1], p3[0], p3[1], routeColor, 150);
			this.getSurface().drawLineAlpha(p3[0], p3[1], p0[0], p0[1], routeColor, 150);
		}
	}

	private boolean projectWorldWalkTileCorner(final int index, final int sceneX, final int sceneZ) {
		final int sceneY = -this.world.getElevation(sceneX, sceneZ) - 2;
		return this.scene.projectToScreen(sceneX, sceneY, sceneZ, this.worldWalkSceneTileProjection[index]);
	}

	private void drawPendingInputMarker() {
		if (!this.pendingInputMarkerActive || this.world == null || this.scene == null || this.localPlayer == null) {
			return;
		}

		long ageMillis = System.currentTimeMillis() - this.pendingInputMarkerStartMillis;
		if (ageMillis >= PENDING_INPUT_MARKER_MILLIS
			|| this.pendingInputMarkerLocalX < 0
			|| this.pendingInputMarkerLocalZ < 0
			|| this.pendingInputMarkerLocalX >= 95
			|| this.pendingInputMarkerLocalZ >= 95
			|| localPlayerTileX() == this.pendingInputMarkerLocalX
			&& localPlayerTileZ() == this.pendingInputMarkerLocalZ) {
			clearPendingInputMarker();
			return;
		}

		final int localX = this.pendingInputMarkerLocalX;
		final int localZ = this.pendingInputMarkerLocalZ;
		final int x0 = localX * this.tileSize;
		final int z0 = localZ * this.tileSize;
		final int x1 = x0 + this.tileSize;
		final int z1 = z0 + this.tileSize;
		if (!projectPendingInputMarkerCorner(0, x0, z0)) return;
		if (!projectPendingInputMarkerCorner(1, x1, z0)) return;
		if (!projectPendingInputMarkerCorner(2, x1, z1)) return;
		if (!projectPendingInputMarkerCorner(3, x0, z1)) return;

		int fade = (int)(PENDING_INPUT_MARKER_MILLIS - ageMillis);
		int pulse = 14 + ((this.getFrameCounter() / 2) & 7);
		int fillAlpha = Math.max(18, Math.min(70, fade * 70 / (int)PENDING_INPUT_MARKER_MILLIS));
		int edgeAlpha = Math.max(70, Math.min(190, fade * 190 / (int)PENDING_INPUT_MARKER_MILLIS + pulse));
		final int fillColor = 0x2AD28C;
		final int edgeColor = 0xA8FFD6;
		final int[] p0 = this.pendingInputMarkerProjection[0];
		final int[] p1 = this.pendingInputMarkerProjection[1];
		final int[] p2 = this.pendingInputMarkerProjection[2];
		final int[] p3 = this.pendingInputMarkerProjection[3];
		this.getSurface().drawQuadrilateralAlpha(p0[0], p0[1], p1[0], p1[1], p2[0], p2[1],
			p3[0], p3[1], fillColor, fillAlpha);
		this.getSurface().drawLineAlpha(p0[0], p0[1], p1[0], p1[1], edgeColor, edgeAlpha);
		this.getSurface().drawLineAlpha(p1[0], p1[1], p2[0], p2[1], edgeColor, edgeAlpha);
		this.getSurface().drawLineAlpha(p2[0], p2[1], p3[0], p3[1], edgeColor, edgeAlpha);
		this.getSurface().drawLineAlpha(p3[0], p3[1], p0[0], p0[1], edgeColor, edgeAlpha);
		drawPendingInputMarkerCenter(localX, localZ, edgeColor, edgeAlpha);
	}

	private boolean projectPendingInputMarkerCorner(final int index, final int sceneX, final int sceneZ) {
		final int sceneY = -this.world.getElevation(sceneX, sceneZ) - 3;
		return this.scene.projectToScreen(sceneX, sceneY, sceneZ, this.pendingInputMarkerProjection[index]);
	}

	private void drawPendingInputMarkerCenter(final int localX, final int localZ, final int color, final int alpha) {
		final int sceneX = localX * this.tileSize + 64;
		final int sceneZ = localZ * this.tileSize + 64;
		final int sceneY = -this.world.getElevation(sceneX, sceneZ) - 14;
		if (!this.scene.projectToScreen(sceneX, sceneY, sceneZ, this.pendingInputMarkerCenterProjection)) {
			return;
		}

		final int x = this.pendingInputMarkerCenterProjection[0];
		final int y = this.pendingInputMarkerCenterProjection[1];
		final int radius = 5 + ((this.getFrameCounter() / 3) & 3);
		this.getSurface().drawLineAlpha(x, y - radius, x + radius, y, color, alpha);
		this.getSurface().drawLineAlpha(x + radius, y, x, y + radius, color, alpha);
		this.getSurface().drawLineAlpha(x, y + radius, x - radius, y, color, alpha);
		this.getSurface().drawLineAlpha(x - radius, y, x, y - radius, color, alpha);
	}

	private void drawFpsOverlay() {
		if (this.getSurface() == null) {
			return;
		}
		if (this.vitalsHudHidden && useVoidscapeHudSkin()) {
			return;
		}
		if (isShowDialogBank()) {
			return; // hide the FPS counter while banking for clean space
		}
		if (this.optionsMenuShow) {
			return; // hide the vitals stack under option menus / card pickers
		}

		String label = "FPS " + FPS;
		if (voidscapeUseMobilePanelShell()) {
			int width = 76;
			int height = 30;
			int x = this.getGameWidth() - width - 7;
			int y = 7;
			drawVoidscapeSkinSprite("top-tab-normal.png", x, y, width, height);
			this.getSurface().drawBoxAlpha(x + 6, y + 5, width - 12, height - 10, UiSkin.VOID_BODY, 70);
			this.getSurface().drawColoredStringCentered(x + width / 2, label, UiSkin.TEXT_BODY, 0, 1, y + 20);
			drawVoidscapeVitalsBars(x + width - VOID_VITALS_BAR_W, y + height + 4);
			return;
		}
		int x = 7;
		if (useVoidscapeHudSkin()) {
			// Left vitals stack (RSCRevolution-style placement): FPS chip in the
			// same glass-bar card as Hits/Prayer, anchored ~38% down the frame so
			// the stack scales with window height (y=126 at the classic 334).
			int stackY = this.getGameHeight() * 38 / 100;
			this.getSurface().drawBoxAlpha(x, stackY, VOID_VITALS_BAR_W, VOID_VITALS_BAR_H,
				UiSkin.GLASS_BODY, UiSkin.A_GLASS_TEXT);
			// FPS wears the fatigue-bar grey from the reference (subtle full wash).
			this.getSurface().drawBoxAlpha(x + 1, stackY + 1, VOID_VITALS_BAR_W - 2,
				VOID_VITALS_BAR_H - 2, UiSkin.VITAL_META, 56);
			this.getSurface().drawBorder(x, stackY, VOID_VITALS_BAR_W, VOID_VITALS_BAR_H, UiSkin.GLASS_RIM);
			this.getSurface().drawString(label, x + 5, stackY + 12, UiSkin.TEXT_BODY, UiSkin.FONT_SMALL);
			drawVoidscapeVitalsBars(x, stackY + VOID_VITALS_BAR_H + 2);
			return;
		}
		int y = 42;
		int width = this.getSurface().stringWidth(1, label) + 12;
		this.getSurface().drawBoxAlpha(x, y, width, 16, UiSkin.VOID_BODY, 150);
		this.getSurface().drawBoxBorder(x, width, y, 16, UiSkin.VOID_LINE);
		this.getSurface().drawString(label, x + 6, y + 12, UiSkin.TEXT_BODY, UiSkin.FONT_BODY);
	}

	private static final int VOID_VITALS_BAR_W = 110;
	private static final int VOID_VITALS_BAR_H = 16;

	/**
	 * Hits + Prayer as stacked translucent glass bars (all void-skin platforms;
	 * replaces the old text-only mobile vitals overlay). Fill width tracks the
	 * current/max fraction; hits flip to the danger color at 30%.
	 */
	private void drawVoidscapeVitalsBars(int x, int y) {
		if (!useVoidscapeHudSkin() || this.currentViewMode != GameMode.GAME
			|| this.playerStatCurrent == null || this.playerStatCurrent.length <= 5
			|| this.playerStatBase == null || this.playerStatBase.length <= 5) {
			return;
		}
		drawVoidscapeVitalBar(x, y, "Hits", this.playerStatCurrent[3], this.playerStatBase[3], UiSkin.VITAL_HITS);
		drawVoidscapeVitalBar(x, y + VOID_VITALS_BAR_H + 2, "Prayer",
			this.playerStatCurrent[5], this.playerStatBase[5], UiSkin.VITAL_PRAYER);
	}

	private void drawVoidscapeVitalBar(int x, int y, String label, int current, int max, int fillColor) {
		int safeMax = Math.max(1, max);
		int fillW = Math.max(0, Math.min(VOID_VITALS_BAR_W - 2, (VOID_VITALS_BAR_W - 2) * current / safeMax));
		this.getSurface().drawBoxAlpha(x, y, VOID_VITALS_BAR_W, VOID_VITALS_BAR_H,
			UiSkin.GLASS_BODY, UiSkin.A_GLASS_TEXT);
		if (fillW > 0) {
			this.getSurface().drawBoxAlpha(x + 1, y + 1, fillW, VOID_VITALS_BAR_H - 2, fillColor, 120);
		}
		this.getSurface().drawBorder(x, y, VOID_VITALS_BAR_W, VOID_VITALS_BAR_H, UiSkin.GLASS_RIM);
		this.getSurface().drawString(label + " " + current + "/" + max, x + 5, y + 12,
			UiSkin.TEXT_BODY, UiSkin.FONT_SMALL);
	}

	public void toggleTerrainEditorMode() {
		if (this.localPlayer == null || !this.localPlayer.isDev()) {
			this.showMessage(false, null, "@or1@Terrain editor mode is dev-only.", MessageType.GAME, 0, null);
			return;
		}
		this.terrainEditorMode = !this.terrainEditorMode;
		this.terrainEditorHoverLocalX = -1;
		this.terrainEditorHoverLocalZ = -1;
		this.mouseButtonClick = 0;
		this.lastMouseButtonDown = 0;
		this.currentMouseButtonDown = 0;
		this.showMessage(false, null, this.terrainEditorMode
			? "@gre@Terrain editor Phase 3: brush edit mode enabled."
			: "@or1@Terrain editor disabled.", MessageType.GAME, 0, null);
	}

	public boolean handleTerrainEditorKey(final char keyChar, final int keyCode) {
		if (!this.terrainEditorMode) return false;

		final char key = Character.toLowerCase(keyChar);
		if (key == '1') {
			this.terrainEditorAction = TerrainEditorAction.RAISE;
		} else if (key == '2') {
			this.terrainEditorAction = TerrainEditorAction.LOWER;
		} else if (key == '3') {
			this.terrainEditorAction = TerrainEditorAction.SMOOTH;
		} else if (key == '4') {
			this.terrainEditorAction = TerrainEditorAction.FLATTEN;
		} else if (key == '5') {
			this.terrainEditorAction = TerrainEditorAction.PAINT_WATER;
		} else if (key == '6') {
			this.terrainEditorAction = TerrainEditorAction.PAINT_GRASS;
		} else if (key == '7') {
			this.terrainEditorAction = TerrainEditorAction.PAINT_STONE;
		} else if (key == '[') {
			this.terrainEditorBrushRadius = Math.max(0, this.terrainEditorBrushRadius - 1);
		} else if (key == ']') {
			this.terrainEditorBrushRadius = Math.min(8, this.terrainEditorBrushRadius + 1);
		} else if (key == '-' || key == '_') {
			this.terrainEditorHeightStep = Math.max(1, this.terrainEditorHeightStep - 1);
		} else if (key == '=' || key == '+') {
			this.terrainEditorHeightStep = Math.min(32, this.terrainEditorHeightStep + 1);
		} else if (key == 'u') {
			terrainEditorUndo();
			return true;
		} else if (key == 'y') {
			terrainEditorRedo();
			return true;
		} else {
			return false;
		}

		this.showMessage(false, null, "@gre@Terrain editor: @whi@" + terrainEditorAction.label
			+ " @gre@radius @whi@" + this.terrainEditorBrushRadius
			+ " @gre@step @whi@" + this.terrainEditorHeightStep, MessageType.GAME, 0, null);
		return true;
	}

	private void drawTerrainEditorHoverOverlay() {
		if (!this.terrainEditorMode || this.world == null || this.scene == null) return;
		final int tileIndex = this.getHoveredLandscapeTileIndex();
		if (tileIndex < 0) {
			this.terrainEditorHoverLocalX = -1;
			this.terrainEditorHoverLocalZ = -1;
			this.getSurface().drawString("Terrain editor: no terrain tile", 7, 34, 0xFFC040, 1);
			return;
		}

		final int localX = this.world.faceTileX[tileIndex];
		final int localZ = this.world.faceTileZ[tileIndex];
		if (localX < 0 || localZ < 0 || localX >= 95 || localZ >= 95) return;

		this.terrainEditorHoverLocalX = localX;
		this.terrainEditorHoverLocalZ = localZ;
		handleTerrainEditorTileClick(localX, localZ);
		drawTerrainEditorBrushOverlay(localX, localZ);
		this.getSurface().drawString("Terrain editor: tile @gre@(" + (this.midRegionBaseX + localX)
			+ "," + (this.midRegionBaseZ + localZ) + "@whi@) action @gre@"
			+ this.terrainEditorAction.label + "@whi@ radius @gre@" + this.terrainEditorBrushRadius
			+ "@whi@ step @gre@" + this.terrainEditorHeightStep, 7, 34, 0xFFFFFF, 1);
		this.getSurface().drawString("material: tex @gre@" + this.world.terrainEditorGetGroundTexture(localX, localZ)
			+ "@whi@ overlay @gre@" + this.world.terrainEditorGetGroundOverlay(localX, localZ)
			+ "@whi@ height @gre@" + this.world.terrainEditorGetStoredElevation(localX, localZ)
			+ "@whi@ undo @gre@" + this.terrainEditorUndoStack.size()
			+ "@whi@ redo @gre@" + this.terrainEditorRedoStack.size(), 7, 47, 0xFFFFFF, 1);
	}

	private boolean projectTerrainEditorTileCorner(final int index, final int sceneX, final int sceneZ) {
		final int sceneY = -this.world.getElevation(sceneX, sceneZ) - 4;
		return this.scene.projectToScreen(sceneX, sceneY, sceneZ, this.terrainEditorTileProjection[index]);
	}

	private void drawTerrainEditorBrushOverlay(final int centerLocalX, final int centerLocalZ) {
		for (int dx = -this.terrainEditorBrushRadius; dx <= this.terrainEditorBrushRadius; dx++) {
			for (int dz = -this.terrainEditorBrushRadius; dz <= this.terrainEditorBrushRadius; dz++) {
				if (!isTerrainEditorBrushTile(dx, dz)) continue;
				final int localX = centerLocalX + dx;
				final int localZ = centerLocalZ + dz;
				if (localX < 0 || localZ < 0 || localX >= 95 || localZ >= 95) continue;
				final boolean center = dx == 0 && dz == 0;
				drawTerrainEditorTileOverlay(localX, localZ, center ? 0x9A4DFF : 0x6D38D8,
					center ? 95 : 45, center ? 0xFFE66D : 0xB58DFF, center ? 235 : 130);
			}
		}
	}

	private void drawTerrainEditorTileOverlay(final int localX, final int localZ, final int fillColor,
											  final int fillAlpha, final int edgeColor, final int edgeAlpha) {
		final int x0 = localX * this.tileSize;
		final int z0 = localZ * this.tileSize;
		final int x1 = x0 + this.tileSize;
		final int z1 = z0 + this.tileSize;
		if (!projectTerrainEditorTileCorner(0, x0, z0)) return;
		if (!projectTerrainEditorTileCorner(1, x1, z0)) return;
		if (!projectTerrainEditorTileCorner(2, x1, z1)) return;
		if (!projectTerrainEditorTileCorner(3, x0, z1)) return;

		final int[] p0 = this.terrainEditorTileProjection[0];
		final int[] p1 = this.terrainEditorTileProjection[1];
		final int[] p2 = this.terrainEditorTileProjection[2];
		final int[] p3 = this.terrainEditorTileProjection[3];
		this.getSurface().drawQuadrilateralAlpha(p0[0], p0[1], p1[0], p1[1], p2[0], p2[1],
			p3[0], p3[1], fillColor, fillAlpha);
		this.getSurface().drawLineAlpha(p0[0], p0[1], p1[0], p1[1], edgeColor, edgeAlpha);
		this.getSurface().drawLineAlpha(p1[0], p1[1], p2[0], p2[1], edgeColor, edgeAlpha);
		this.getSurface().drawLineAlpha(p2[0], p2[1], p3[0], p3[1], edgeColor, edgeAlpha);
		this.getSurface().drawLineAlpha(p3[0], p3[1], p0[0], p0[1], edgeColor, edgeAlpha);
	}

	private void handleTerrainEditorTileClick(final int localX, final int localZ) {
		if (this.mouseButtonClick != 1) return;

		final TerrainEditorEdit edit = applyTerrainEditorBrush(localX, localZ);
		this.mouseButtonClick = 0;
		this.lastMouseButtonDown = 0;
		this.currentMouseButtonDown = 0;
		if (edit != null && edit.hasChanges()) {
			pushTerrainEditorUndo(edit);
			rebuildTerrainEditorRegion();
		}
	}

	private TerrainEditorEdit applyTerrainEditorBrush(final int centerLocalX, final int centerLocalZ) {
		if (this.world == null || this.lastHeightOffset < 0) return null;

		final TerrainEditorEdit edit = new TerrainEditorEdit();
		if (this.terrainEditorAction == TerrainEditorAction.PAINT_WATER
			|| this.terrainEditorAction == TerrainEditorAction.PAINT_GRASS
			|| this.terrainEditorAction == TerrainEditorAction.PAINT_STONE) {
			applyTerrainEditorPaintBrush(edit, centerLocalX, centerLocalZ);
		} else {
			applyTerrainEditorHeightBrush(edit, centerLocalX, centerLocalZ);
		}
		return edit;
	}

	private void applyTerrainEditorPaintBrush(final TerrainEditorEdit edit,
											  final int centerLocalX, final int centerLocalZ) {
		for (int dx = -this.terrainEditorBrushRadius; dx <= this.terrainEditorBrushRadius; dx++) {
			for (int dz = -this.terrainEditorBrushRadius; dz <= this.terrainEditorBrushRadius; dz++) {
				if (!isTerrainEditorBrushTile(dx, dz)) continue;
				final int localX = centerLocalX + dx;
				final int localZ = centerLocalZ + dz;
				if (localX < 0 || localZ < 0 || localX >= 95 || localZ >= 95) continue;

				final int archiveX = this.midRegionBaseX + this.worldOffsetX + localX;
				final int archiveZ = this.midRegionBaseZ + this.worldOffsetZ + localZ;
				captureTerrainEditorPaint(edit.beforePaint, this.lastHeightOffset, archiveX, archiveZ, localX, localZ);

				if (this.terrainEditorAction == TerrainEditorAction.PAINT_WATER) {
					this.world.terrainEditorPaintTile(this.lastHeightOffset, archiveX, archiveZ,
						localX, localZ, -1, TERRAIN_EDITOR_WATER_OVERLAY);
				} else if (this.terrainEditorAction == TerrainEditorAction.PAINT_GRASS) {
					this.world.terrainEditorPaintTile(this.lastHeightOffset, archiveX, archiveZ,
						localX, localZ, TERRAIN_EDITOR_GRASS_TEXTURE, 0);
				} else if (this.terrainEditorAction == TerrainEditorAction.PAINT_STONE) {
					this.world.terrainEditorPaintTile(this.lastHeightOffset, archiveX, archiveZ,
						localX, localZ, -1, TERRAIN_EDITOR_STONE_OVERLAY);
				}

				captureTerrainEditorPaint(edit.afterPaint, this.lastHeightOffset, archiveX, archiveZ, localX, localZ);
			}
		}
	}

	private void applyTerrainEditorHeightBrush(final TerrainEditorEdit edit,
											   final int centerLocalX, final int centerLocalZ) {
		final LinkedHashMap<Long, TerrainEditorHeightSample> samples = collectTerrainEditorHeightSamples(
			centerLocalX, centerLocalZ);
		if (samples.isEmpty()) return;

		final LinkedHashMap<Long, Integer> targets = new LinkedHashMap<>();
		if (this.terrainEditorAction == TerrainEditorAction.FLATTEN) {
			final int flattenHeight = terrainEditorCenterHeight(centerLocalX, centerLocalZ);
			for (Long key : samples.keySet()) {
				targets.put(key, flattenHeight);
			}
		} else if (this.terrainEditorAction == TerrainEditorAction.SMOOTH) {
			for (Entry<Long, TerrainEditorHeightSample> entry : samples.entrySet()) {
				final TerrainEditorHeightSample sample = entry.getValue();
				final int current = this.world.terrainEditorGetStoredElevation(sample.localX, sample.localZ);
				final int average = terrainEditorAverageNeighborHeight(sample.localX, sample.localZ);
				if (current >= 0 && average >= 0) {
					targets.put(entry.getKey(), (current + average) / 2);
				}
			}
		} else {
			for (Entry<Long, TerrainEditorHeightSample> entry : samples.entrySet()) {
				final TerrainEditorHeightSample sample = entry.getValue();
				final int current = this.world.terrainEditorGetStoredElevation(sample.localX, sample.localZ);
				if (current >= 0) {
					targets.put(entry.getKey(), current + sample.delta);
				}
			}
		}

		for (Entry<Long, TerrainEditorHeightSample> entry : samples.entrySet()) {
			final Integer target = targets.get(entry.getKey());
			if (target == null) continue;

			final TerrainEditorHeightSample sample = entry.getValue();
			captureTerrainEditorHeight(edit.beforeHeights, this.lastHeightOffset,
				sample.archiveX, sample.archiveZ, sample.localX, sample.localZ);
			this.world.terrainEditorSetVertexHeight(this.lastHeightOffset, sample.archiveX, sample.archiveZ,
				sample.localX, sample.localZ, target);
			captureTerrainEditorHeight(edit.afterHeights, this.lastHeightOffset,
				sample.archiveX, sample.archiveZ, sample.localX, sample.localZ);
		}
	}

	private LinkedHashMap<Long, TerrainEditorHeightSample> collectTerrainEditorHeightSamples(
		final int centerLocalX, final int centerLocalZ) {
		final LinkedHashMap<Long, TerrainEditorHeightSample> samples = new LinkedHashMap<>();
		for (int dx = -this.terrainEditorBrushRadius; dx <= this.terrainEditorBrushRadius; dx++) {
			for (int dz = -this.terrainEditorBrushRadius; dz <= this.terrainEditorBrushRadius; dz++) {
				if (!isTerrainEditorBrushTile(dx, dz)) continue;
				final int localX = centerLocalX + dx;
				final int localZ = centerLocalZ + dz;
				if (localX < 0 || localZ < 0 || localX >= 95 || localZ >= 95) continue;

				final int brushDelta = terrainEditorBrushDelta(dx, dz);
				addTerrainEditorHeightSample(samples, localX, localZ, brushDelta);
				addTerrainEditorHeightSample(samples, localX + 1, localZ, brushDelta);
				addTerrainEditorHeightSample(samples, localX, localZ + 1, brushDelta);
				addTerrainEditorHeightSample(samples, localX + 1, localZ + 1, brushDelta);
			}
		}
		return samples;
	}

	private void addTerrainEditorHeightSample(final LinkedHashMap<Long, TerrainEditorHeightSample> samples,
											  final int localX, final int localZ, final int delta) {
		if (localX < 0 || localZ < 0 || localX >= 96 || localZ >= 96) return;
		final int archiveX = this.midRegionBaseX + this.worldOffsetX + localX;
		final int archiveZ = this.midRegionBaseZ + this.worldOffsetZ + localZ;
		final long key = terrainEditorSnapshotKey(this.lastHeightOffset, archiveX, archiveZ);
		final TerrainEditorHeightSample existing = samples.get(key);
		if (existing == null) {
			samples.put(key, new TerrainEditorHeightSample(localX, localZ, archiveX, archiveZ, delta));
		} else if (Math.abs(delta) > Math.abs(existing.delta)) {
			existing.delta = delta;
		}
	}

	private int terrainEditorBrushDelta(final int dx, final int dz) {
		if (this.terrainEditorAction != TerrainEditorAction.RAISE
			&& this.terrainEditorAction != TerrainEditorAction.LOWER) return 0;
		int amount = this.terrainEditorHeightStep;
		if (this.terrainEditorBrushRadius > 0) {
			final double distance = Math.sqrt(dx * dx + dz * dz);
			final double falloff = Math.max(0.25D, 1.0D - distance / (this.terrainEditorBrushRadius + 1.0D));
			amount = Math.max(1, (int) Math.round(this.terrainEditorHeightStep * falloff));
		}
		return this.terrainEditorAction == TerrainEditorAction.LOWER ? -amount : amount;
	}

	private boolean isTerrainEditorBrushTile(final int dx, final int dz) {
		if (this.terrainEditorBrushRadius <= 0) return dx == 0 && dz == 0;
		return dx * dx + dz * dz <= this.terrainEditorBrushRadius * this.terrainEditorBrushRadius;
	}

	private int terrainEditorCenterHeight(final int localX, final int localZ) {
		int total = 0;
		int count = 0;
		for (int dx = 0; dx <= 1; dx++) {
			for (int dz = 0; dz <= 1; dz++) {
				final int height = this.world.terrainEditorGetStoredElevation(localX + dx, localZ + dz);
				if (height >= 0) {
					total += height;
					count++;
				}
			}
		}
		return count == 0 ? 0 : total / count;
	}

	private int terrainEditorAverageNeighborHeight(final int localX, final int localZ) {
		int total = 0;
		int count = 0;
		for (int dx = -1; dx <= 1; dx++) {
			for (int dz = -1; dz <= 1; dz++) {
				final int height = this.world.terrainEditorGetStoredElevation(localX + dx, localZ + dz);
				if (height >= 0) {
					total += height;
					count++;
				}
			}
		}
		return count == 0 ? -1 : total / count;
	}

	private void captureTerrainEditorHeight(final LinkedHashMap<Long, TerrainEditorHeightSnapshot> target,
											final int plane, final int archiveX, final int archiveZ,
											final int localX, final int localZ) {
		final long key = terrainEditorSnapshotKey(plane, archiveX, archiveZ);
		if (target.containsKey(key)) return;
		final int height = this.world.terrainEditorGetStoredElevation(localX, localZ);
		if (height >= 0) {
			target.put(key, new TerrainEditorHeightSnapshot(plane, archiveX, archiveZ, height));
		}
	}

	private void captureTerrainEditorPaint(final LinkedHashMap<Long, TerrainEditorPaintSnapshot> target,
										   final int plane, final int archiveX, final int archiveZ,
										   final int localX, final int localZ) {
		final long key = terrainEditorSnapshotKey(plane, archiveX, archiveZ);
		if (target.containsKey(key)) return;
		final int groundTexture = this.world.terrainEditorGetGroundTexture(localX, localZ);
		final int groundOverlay = this.world.terrainEditorGetGroundOverlay(localX, localZ);
		if (groundTexture >= 0 && groundOverlay >= 0) {
			target.put(key, new TerrainEditorPaintSnapshot(plane, archiveX, archiveZ, groundTexture, groundOverlay));
		}
	}

	private void pushTerrainEditorUndo(final TerrainEditorEdit edit) {
		this.terrainEditorUndoStack.addLast(edit);
		while (this.terrainEditorUndoStack.size() > TERRAIN_EDITOR_MAX_UNDO) {
			this.terrainEditorUndoStack.removeFirst();
		}
		this.terrainEditorRedoStack.clear();
	}

	private void terrainEditorUndo() {
		if (this.terrainEditorUndoStack.isEmpty()) {
			this.showMessage(false, null, "@or1@Terrain editor: nothing to undo.", MessageType.GAME, 0, null);
			return;
		}
		final TerrainEditorEdit edit = this.terrainEditorUndoStack.removeLast();
		applyTerrainEditorSnapshots(edit, false);
		this.terrainEditorRedoStack.addLast(edit);
		rebuildTerrainEditorRegion();
	}

	private void terrainEditorRedo() {
		if (this.terrainEditorRedoStack.isEmpty()) {
			this.showMessage(false, null, "@or1@Terrain editor: nothing to redo.", MessageType.GAME, 0, null);
			return;
		}
		final TerrainEditorEdit edit = this.terrainEditorRedoStack.removeLast();
		applyTerrainEditorSnapshots(edit, true);
		this.terrainEditorUndoStack.addLast(edit);
		rebuildTerrainEditorRegion();
	}

	private void applyTerrainEditorSnapshots(final TerrainEditorEdit edit, final boolean after) {
		final LinkedHashMap<Long, TerrainEditorHeightSnapshot> heights = after
			? edit.afterHeights
			: edit.beforeHeights;
		for (TerrainEditorHeightSnapshot snapshot : heights.values()) {
			final int localX = snapshot.archiveX - this.midRegionBaseX - this.worldOffsetX;
			final int localZ = snapshot.archiveZ - this.midRegionBaseZ - this.worldOffsetZ;
			this.world.terrainEditorSetVertexHeight(snapshot.plane, snapshot.archiveX, snapshot.archiveZ,
				localX, localZ, snapshot.height);
		}

		final LinkedHashMap<Long, TerrainEditorPaintSnapshot> paint = after
			? edit.afterPaint
			: edit.beforePaint;
		for (TerrainEditorPaintSnapshot snapshot : paint.values()) {
			final int localX = snapshot.archiveX - this.midRegionBaseX - this.worldOffsetX;
			final int localZ = snapshot.archiveZ - this.midRegionBaseZ - this.worldOffsetZ;
			this.world.terrainEditorPaintTile(snapshot.plane, snapshot.archiveX, snapshot.archiveZ,
				localX, localZ, snapshot.groundTexture, snapshot.groundOverlay);
		}
	}

	private static long terrainEditorSnapshotKey(final int plane, final int archiveX, final int archiveZ) {
		return ((long) (plane & 0xff) << 56)
			| ((long) archiveX & 0x0fffffffL) << 28
			| ((long) archiveZ & 0x0fffffffL);
	}

	private void rebuildTerrainEditorRegion() {
		if (this.world == null || this.localPlayer == null || this.lastHeightOffset < 0) return;
		final int wantX = this.playerLocalX + this.midRegionBaseX + this.worldOffsetX;
		final int wantZ = this.playerLocalZ + this.midRegionBaseZ + this.worldOffsetZ;
		applyWorldReskinForRegion(wantX - this.worldOffsetX, wantZ - this.worldOffsetZ);
		this.world.loadSections(wantX, wantZ, this.lastHeightOffset);
		markRoofVisibilitySceneModelsLoaded();
		readdTerrainEditorSceneModels();
		this.world.playerAlive = true;
	}

	private void readdTerrainEditorSceneModels() {
		for (int i = 0; i < this.gameObjectInstanceCount; ++i) {
			final int xTile = this.gameObjectInstanceX[i];
			final int zTile = this.gameObjectInstanceZ[i];
			final int objectID = this.gameObjectInstanceID[i];
			final RSModel model = this.gameObjectInstanceModel[i];
			if (model == null) continue;

			try {
				final int dir = this.gameObjectInstanceDir[i];
				this.world.registerObjectDir(xTile, zTile, dir);
				final int xSize;
				final int zSize;
				if (dir == 0 || dir == 4) {
					xSize = EntityHandler.getObjectDef(objectID).getWidth();
					zSize = EntityHandler.getObjectDef(objectID).getHeight();
				} else {
					xSize = EntityHandler.getObjectDef(objectID).getHeight();
					zSize = EntityHandler.getObjectDef(objectID).getWidth();
				}

				final int x = (2 * xTile + xSize) * this.tileSize / 2;
				final int z = this.tileSize * (2 * zTile + zSize) / 2;
				if (xTile >= 0 && zTile >= 0 && xTile < 96 && zTile < 96) {
					this.scene.addModel(model);
					model.setTranslate(x, -this.world.getElevation(x, z), z);
					this.world.addGameObject_UpdateCollisionMap(xTile, zTile, objectID, false);
					if (objectID == 74) {
						model.translate2(0, -480, 0);
					}
				}
			} catch (RuntimeException ex) {
				System.out.println("Terrain editor loc rebuild error: " + ex.getMessage());
				ex.printStackTrace();
			}
		}

		for (int i = 0; i < this.wallObjectInstanceCount; ++i) {
			final int xTile = this.wallObjectInstanceX[i];
			final int zTile = this.wallObjectInstanceZ[i];
			final int id = this.wallObjectInstanceID[i];
			final int dir = this.wallObjectInstanceDir[i];
			try {
				this.world.registerObjectDir(xTile, zTile, dir);
				this.world.applyWallToCollisionFlags(id, xTile, zTile, dir);
				this.wallObjectInstanceModel[i] = this.createWallObjectModel(xTile, zTile, id, dir, i);
			} catch (RuntimeException ex) {
				System.out.println("Terrain editor wall rebuild error: " + ex.getMessage());
				ex.printStackTrace();
			}
		}
	}

	private void queueVoidScoutBodySprite() {
		if (!this.voidScoutActive || this.localPlayer == null || this.playerCount >= this.players.length) return;

		final int localTileX = this.voidScoutBodyX - this.midRegionBaseX;
		final int localTileZ = this.voidScoutBodyY - this.midRegionBaseZ;
		if (localTileX < 0 || localTileZ < 0 || localTileX >= 96 || localTileZ >= 96) return;

		final int sceneX = localTileX * this.tileSize + 64;
		final int sceneZ = localTileZ * this.tileSize + 64;
		final int sceneY = -this.world.getElevation(sceneX, sceneZ);
		final int slot = this.playerCount;
		final ORSCharacter bodyMarker = createVoidScoutBodyMarker(sceneX, sceneZ);

		this.voidScoutBodySpriteIndex = slot;
		this.voidScoutBodyPreviousPlayer = this.players[slot];
		this.players[slot] = bodyMarker;

		int sprite = this.scene.drawSprite(slot + 5000, sceneZ, slot + 10000, sceneX, sceneY, 145, 220, (byte) 109);
		++this.spriteCount;
		this.scene.setFaceSpriteLocalPlayer('\u8000', sprite);
	}

	private ORSCharacter createVoidScoutBodyMarker(final int sceneX, final int sceneZ) {
		final ORSCharacter marker = new ORSCharacter();
		marker.accountName = this.localPlayer.accountName;
		marker.displayName = this.localPlayer.displayName;
		marker.title = this.localPlayer.title;
		marker.groupID = this.localPlayer.groupID;
		marker.serverIndex = this.localPlayer.serverIndex;
		marker.colourBottom = this.localPlayer.colourBottom;
		marker.colourHair = this.localPlayer.colourHair;
		marker.hairStyle = this.localPlayer.hairStyle;
		marker.colourSkin = this.localPlayer.colourSkin;
		marker.colourTop = this.localPlayer.colourTop;
		marker.wield = this.localPlayer.wield;
		marker.wield2 = this.localPlayer.wield2;
		marker.skull = this.localPlayer.skull;
		marker.skullVisible = this.localPlayer.skullVisible;
		marker.level = this.localPlayer.level;
		marker.healthCurrent = this.localPlayer.healthCurrent;
		marker.healthMax = this.localPlayer.healthMax;
		marker.isInvisible = this.localPlayer.isInvisible;
		marker.isInvulnerable = this.localPlayer.isInvulnerable;
		System.arraycopy(this.localPlayer.layerAnimation, 0, marker.layerAnimation, 0, marker.layerAnimation.length);
		marker.currentX = sceneX;
		marker.currentZ = sceneZ;
		marker.waypointIndexCurrent = 0;
		marker.waypointIndexNext = 0;
		marker.waypointsX[0] = sceneX;
		marker.waypointsZ[0] = sceneZ;
		marker.stepFrame = 0;
		marker.direction = this.voidScoutBodyDirection;
		marker.animationNext = this.voidScoutBodyDirection.rsDir;
		marker.bubbleTimeout = 1;
		marker.bubbleItem = VOID_SPARROW_ITEM_ID;
		return marker;
	}

	private void clearQueuedVoidScoutBodySprite() {
		if (this.voidScoutBodySpriteIndex < 0) return;

		this.players[this.voidScoutBodySpriteIndex] = this.voidScoutBodyPreviousPlayer;
		this.voidScoutBodySpriteIndex = -1;
		this.voidScoutBodyPreviousPlayer = null;
	}

	/**
	 * Top-center timer plaque: delegates to UiSkin.timerBanner (§4.4 — HUD
	 * plaques consume the shared kit). Slot pitch stacks scout timer /
	 * system update / elixir without overlap.
	 */
	private void drawVoidscapeTimerPlaque(int slot, String label, boolean urgent) {
		UiSkin.timerBanner(this.getSurface(), this.getGameWidth(), slot, label, urgent);
	}

	private boolean voidScoutTimerVisible() {
		return this.voidScoutActive && this.voidScoutExpiresAtMillis > 0L;
	}

	private void drawVoidScoutTimer() {
		if (!voidScoutTimerVisible()) return;

		final long remainingMillis = Math.max(0L, this.voidScoutExpiresAtMillis - System.currentTimeMillis());
		final int remainingSeconds = (int) ((remainingMillis + 999L) / 1000L);
		final String label = "Void Sparrow: 0:" + (remainingSeconds < 10 ? "0" : "") + remainingSeconds;
		drawVoidscapeTimerPlaque(0, label, remainingSeconds <= 5);
	}

	private boolean isAndroidSmokeFilePresent(final String fileName) {
		return isAndroid()
			&& (isFileInDirectory(Config.F_CACHE_DIR, fileName)
			|| isFileInDirectory(Config.F_ANDROID_SMOKE_DIR, fileName));
	}

	private boolean isFileInDirectory(final String directory, final String fileName) {
		return directory != null
			&& !directory.isEmpty()
			&& new File(directory, fileName).isFile();
	}

