	private boolean shouldOfferCredentialSave() {
		return isAndroid() || Remember();
	}

	private boolean usesSecureCredentialStore() {
		return isNativeAndroidClient() && this.clientPort != null;
	}

	private CredentialStore credentialStore() {
		if (this.clientPort == null || this.clientPort.getCredentialStore() == null) {
			return CredentialStore.unsupported();
		}
		return this.clientPort.getCredentialStore();
	}

	private String rememberLoginButtonText() {
		if (usesSecureCredentialStore() && this.voidscapeCredentialStoreUnavailable) {
			return "Reset saved";
		}
		return this.voidscapeRememberLoginRequested ? "Remembered" : "Remember";
	}

	private void reconcileRememberLoginIndicator() {
		if (!usesSecureCredentialStore() || this.voidscapeRememberLoginDecisionPending
			|| this.panelLogin == null || this.controlLoginUser < 0) {
			return;
		}
		ensureVoidscapeSavedAccountsLoaded();
		String user = this.panelLogin.getControlText(this.controlLoginUser);
		this.voidscapeRememberLoginRequested = findVoidscapeSavedAccount(user) != null;
	}

	private void loadPreferredCredentialIntoLoginPanel() {
		this.voidscapeRememberLoginRequested = false;
		this.voidscapeRememberLoginDecisionPending = false;
		if (usesSecureCredentialStore()) {
			ensureVoidscapeSavedAccountsLoaded();
			if (this.voidscapeCredentialStoreUnavailable) {
				this.panelLogin.setText(this.controlLoginStatus1, "");
				this.panelLogin.setText(this.controlLoginStatus2,
					"@yel@Saved login unavailable - enter password or reset");
				return;
			}
			VoidscapeSavedAccount selected = findVoidscapeSavedAccount(
				this.voidscapeSelectedCredentialUsername);
			if (selected == null && !this.voidscapeSavedAccounts.isEmpty()) {
				selected = this.voidscapeSavedAccounts.get(0);
			}
			if (selected != null && selected.username != null && selected.password != null) {
				this.panelLogin.setText(this.controlLoginUser, selected.username);
				this.panelLogin.setText(this.controlLoginPass, selected.password);
				this.voidscapeRememberLoginRequested = true;
			}
			return;
		}

		String cred = ClientPort.loadCredentials();
		if (cred.length() <= 0) {
			return;
		}
		String[] split = cred.split(",", 2);
		if (split.length == 2) {
			this.panelLogin.setText(this.controlLoginUser, split[0]);
			this.panelLogin.setText(this.controlLoginPass, split[1]);
			this.voidscapeRememberLoginRequested = true;
		}
	}

	private void handleRememberLoginAction() {
		if (!usesSecureCredentialStore()) {
			String user = this.panelLogin.getControlText(this.controlLoginUser);
			String pass = this.panelLogin.getControlText(this.controlLoginPass);
			boolean saved = saveVoidscapeCredentials(user, pass, true);
			this.panelLogin.setText(this.controlLoginStatus1, "");
			this.panelLogin.setText(this.controlLoginStatus2,
				saved ? "@gre@Credentials Saved" : "@red@Unable to save");
			return;
		}

		if (this.voidscapeCredentialStoreUnavailable) {
			CredentialStore.Result cleared = credentialStore().clear();
			if (cleared.getState() == CredentialStore.State.UNAVAILABLE) {
				this.panelLogin.setText(this.controlLoginStatus1, "");
				this.panelLogin.setText(this.controlLoginStatus2, "@red@Unable to reset saved logins");
				return;
			}
			clearVoidscapeCredentialMemory();
			this.voidscapeSavedAccountsLoaded = true;
			this.panelLogin.setText(this.controlLoginStatus1, "");
			this.panelLogin.setText(this.controlLoginStatus2, "@gre@Saved logins reset");
			return;
		}

		boolean enabling = !this.voidscapeRememberLoginRequested;
		String user = this.panelLogin.getControlText(this.controlLoginUser);
		String pass = this.panelLogin.getControlText(this.controlLoginPass);
		if (enabling && (user == null || user.trim().isEmpty() || pass == null || pass.isEmpty())) {
			this.panelLogin.setText(this.controlLoginStatus1, "");
			this.panelLogin.setText(this.controlLoginStatus2, "@yel@Enter login first");
			return;
		}
		this.voidscapeRememberLoginRequested = enabling;
		this.voidscapeRememberLoginDecisionPending = true;
		this.panelLogin.setText(this.controlLoginStatus1, "");
		this.panelLogin.setText(this.controlLoginStatus2, enabling
			? "@gre@Will remember after a successful login"
			: "@yel@This login won't be saved");
	}

	private void clearVoidscapeCredentialMemory() {
		for (VoidscapeSavedAccount account : this.voidscapeSavedAccounts) {
			account.password = "";
		}
		this.voidscapeSavedAccounts.clear();
		this.voidscapeSelectedCredentialUsername = "";
		this.voidscapeRememberLoginRequested = false;
		this.voidscapeRememberLoginDecisionPending = false;
		this.voidscapeCredentialStoreUnavailable = false;
		this.voidscapeCredentialStoreRetryAt = 0L;
		this.voidscapePendingSwitchUsername = "";
		this.voidscapePendingSwitchPassword = "";
		this.voidscapeAccountAddPendingPass = "";
	}

	private boolean shouldOfferHideIpToggle() {
		return S_WANT_HIDE_IP && !isAndroid();
	}

	private boolean shouldShowLastLoginHost() {
		return !isAndroid() && this.settingsHideIP != null && this.settingsHideIP != 1;
	}

	private File voidscapeAccountsFile() {
		if (Config.F_CACHE_DIR != null && !Config.F_CACHE_DIR.trim().isEmpty()) {
			return new File(Config.F_CACHE_DIR, VOIDSCAPE_ACCOUNTS_FILE);
		}
		return new File(VOIDSCAPE_ACCOUNTS_FILE);
	}

	private String voidscapeAccountKey(String value) {
		if (value == null) {
			return "";
		}
		String key = StringUtil.displayNameToKey(value);
		return key == null ? value.trim().toLowerCase(Locale.ROOT) : key;
	}

	private File worldMapWaypointsFile() {
		if (Config.F_CACHE_DIR != null && !Config.F_CACHE_DIR.trim().isEmpty()) {
			return new File(Config.F_CACHE_DIR, WORLD_MAP_WAYPOINTS_FILE);
		}
		return new File(WORLD_MAP_WAYPOINTS_FILE);
	}

	private String currentWorldMapWaypointAccountKey() {
		String user = getUsername();
		if ((user == null || user.trim().isEmpty()) && this.localPlayer != null) {
			user = this.localPlayer.accountName;
		}
		if ((user == null || user.trim().isEmpty()) && this.localPlayer != null) {
			user = this.localPlayer.displayName;
		}
		String key = voidscapeAccountKey(user);
		return key.isEmpty() ? "default" : key;
	}

	private void ensureWorldMapWaypointsLoaded() {
		String accountKey = currentWorldMapWaypointAccountKey();
		if (this.worldMapWaypointsLoaded && accountKey.equals(this.worldMapWaypointsAccountKey)) {
			return;
		}
		Arrays.fill(this.worldMapWaypoints, null);
		this.worldMapWaypointsLoaded = true;
		this.worldMapWaypointsAccountKey = accountKey;

		File file = worldMapWaypointsFile();
		if (file.isFile()) {
			Properties props = new Properties();
			try (FileInputStream in = new FileInputStream(file)) {
				props.load(in);
				for (int i = 0; i < WORLD_MAP_WAYPOINT_COUNT; i++) {
					String prefix = accountKey + ".slot." + i + ".";
					int x = parseIntOrDefault(props.getProperty(prefix + "x"), -1);
					int y = parseIntOrDefault(props.getProperty(prefix + "y"), -1);
					String name = sanitizeWorldMapWaypointName(props.getProperty(prefix + "name", ""));
					if (isValidWorldMapWaypoint(x, y)) {
						if (name.isEmpty()) {
							name = x + "," + y;
						}
						this.worldMapWaypoints[i] = new WorldMapPanel.Waypoint(x, y, name);
					}
				}
			} catch (IOException ignored) {
			}
		}
		if (this.worldMapWaypoints[0] == null) {
			this.worldMapWaypoints[0] = new WorldMapPanel.Waypoint(
				WORLD_MAP_DEFAULT_WAYPOINT_X,
				WORLD_MAP_DEFAULT_WAYPOINT_Y,
				WORLD_MAP_DEFAULT_WAYPOINT_NAME);
		}
		this.worldMapPanel.setWaypoints(this.worldMapWaypoints);
	}

	private boolean saveWorldMapWaypoints() {
		Properties props = new Properties();
		File file = worldMapWaypointsFile();
		if (file.isFile()) {
			try (FileInputStream in = new FileInputStream(file)) {
				props.load(in);
			} catch (IOException ignored) {
			}
		}

		String prefix = this.worldMapWaypointsAccountKey + ".slot.";
		for (String key : new ArrayList<String>(props.stringPropertyNames())) {
			if (key.startsWith(prefix)) {
				props.remove(key);
			}
		}
		for (int i = 0; i < WORLD_MAP_WAYPOINT_COUNT; i++) {
			WorldMapPanel.Waypoint waypoint = this.worldMapWaypoints[i];
			if (waypoint == null || !waypoint.isSet()) {
				continue;
			}
			String slotPrefix = prefix + i + ".";
			props.setProperty(slotPrefix + "x", Integer.toString(waypoint.worldX));
			props.setProperty(slotPrefix + "y", Integer.toString(waypoint.worldY));
			props.setProperty(slotPrefix + "name", sanitizeWorldMapWaypointName(waypoint.name));
		}

		File parent = file.getParentFile();
		if (parent != null && !parent.isDirectory() && !parent.mkdirs()) {
			return false;
		}
		try (FileOutputStream out = new FileOutputStream(file)) {
			props.store(out, "Voidscape world-map waypoints");
			return true;
		} catch (IOException ignored) {
			return false;
		}
	}

	private void saveWorldMapWaypoint(int slot, int worldX, int worldY) {
		ensureWorldMapWaypointsLoaded();
		if (slot < 0 || slot >= WORLD_MAP_WAYPOINT_COUNT || !isValidWorldMapWaypoint(worldX, worldY)) {
			this.showMessage(false, null, "@red@World map: invalid waypoint.", MessageType.GAME, 0, null);
			return;
		}
		String name = sanitizeWorldMapWaypointName(this.worldMapPanel.describeWorldTile(worldX, worldY));
		if (name.isEmpty()) {
			name = worldX + "," + worldY;
		}
		WorldMapPanel.Waypoint waypoint = new WorldMapPanel.Waypoint(worldX, worldY, name);
		this.worldMapWaypoints[slot] = waypoint;
		this.worldMapPanel.setWaypoint(slot, waypoint);
		if (saveWorldMapWaypoints()) {
			this.showMessage(false, null,
				"@gre@World map: @whi@saved slot " + (slot + 1) + " (" + name + ").",
				MessageType.GAME, 0, null);
		} else {
			this.showMessage(false, null,
				"@red@World map: could not save waypoint.",
				MessageType.GAME, 0, null);
		}
	}

	private boolean isValidWorldMapWaypoint(int worldX, int worldY) {
		return worldX >= 0 && worldX <= 944 && worldY >= 0 && worldY < 944 * 4;
	}

	private String sanitizeWorldMapWaypointName(String name) {
		if (name == null) {
			return "";
		}
		String clean = name.replace('\n', ' ').replace('\r', ' ').trim();
		return clean.length() > 36 ? clean.substring(0, 36) : clean;
	}

	private String voidscapeAccountDisplayName(VoidscapeSavedAccount account) {
		if (account == null) {
			return "";
		}
		if (account.displayName != null && !account.displayName.trim().isEmpty()) {
			return account.displayName.trim();
		}
		return account.username == null ? "" : account.username.trim();
	}

	private void ensureVoidscapeSavedAccountsLoaded() {
		if (this.voidscapeSavedAccountsLoaded) {
			return;
		}
		if (usesSecureCredentialStore()) {
			long now = System.currentTimeMillis();
			if (this.voidscapeCredentialStoreUnavailable && now < this.voidscapeCredentialStoreRetryAt) {
				return;
			}
			CredentialStore.Result result = credentialStore().load();
			if (result.getState() == CredentialStore.State.UNAVAILABLE) {
				this.voidscapeCredentialStoreUnavailable = true;
				this.voidscapeCredentialStoreRetryAt = now + 5000L;
				return;
			}
			applyCredentialSnapshot(result.hasValue()
				? result.getValue()
				: CredentialSnapshot.empty());
			this.voidscapeCredentialStoreUnavailable = false;
			this.voidscapeCredentialStoreRetryAt = 0L;
			this.voidscapeSavedAccountsLoaded = true;
			return;
		}
		this.voidscapeSavedAccountsLoaded = true;
		this.voidscapeSavedAccounts.clear();
		File file = voidscapeAccountsFile();
		if (file.isFile()) {
			Properties props = new Properties();
			try (FileInputStream in = new FileInputStream(file)) {
				props.load(in);
				int count = parseIntOrDefault(props.getProperty("count"), 0);
				for (int i = 0; i < count && this.voidscapeSavedAccounts.size() < VOIDSCAPE_ACCOUNT_MAX; i++) {
					String username = props.getProperty("account." + i + ".username", "").trim();
					String password = props.getProperty("account." + i + ".password", "");
					if (username.isEmpty() || password.isEmpty()) {
						continue;
					}
					VoidscapeSavedAccount account = new VoidscapeSavedAccount();
					account.username = username;
					account.password = password;
					account.displayName = props.getProperty("account." + i + ".displayName", username).trim();
					account.combatLevel = parseIntOrDefault(props.getProperty("account." + i + ".combatLevel"), 0);
					account.lastUsed = parseLongOrDefault(props.getProperty("account." + i + ".lastUsed"), 0L);
					this.voidscapeSavedAccounts.add(account);
				}
			} catch (IOException ignored) {
			}
		}
		if (this.voidscapeSavedAccounts.isEmpty()) {
			loadLegacyCredentialAsVoidscapeAccount();
		}
		sortVoidscapeSavedAccounts();
	}

	private void applyCredentialSnapshot(CredentialSnapshot snapshot) {
		for (VoidscapeSavedAccount account : this.voidscapeSavedAccounts) {
			account.password = "";
		}
		this.voidscapeSavedAccounts.clear();
		this.voidscapeSelectedCredentialUsername = snapshot == null
			|| snapshot.getSelectedUsername() == null
			? ""
			: snapshot.getSelectedUsername().trim();
		if (snapshot == null) {
			return;
		}
		for (SavedCredentialAccount saved : snapshot.getAccounts()) {
			if (this.voidscapeSavedAccounts.size() >= VOIDSCAPE_ACCOUNT_MAX
				|| saved.getUsername().trim().isEmpty() || saved.getPassword().isEmpty()) {
				continue;
			}
			VoidscapeSavedAccount account = new VoidscapeSavedAccount();
			account.username = saved.getUsername().trim();
			account.password = saved.getPassword();
			account.displayName = saved.getDisplayName().trim().isEmpty()
				? account.username
				: saved.getDisplayName().trim();
			account.combatLevel = Math.max(0, saved.getCombatLevel());
			account.lastUsed = Math.max(0L, saved.getLastUsedMillis());
			this.voidscapeSavedAccounts.add(account);
		}
		sortVoidscapeSavedAccounts();
	}

	private int parseIntOrDefault(String value, int fallback) {
		if (value == null) {
			return fallback;
		}
		try {
			return Integer.parseInt(value.trim());
		} catch (NumberFormatException ignored) {
			return fallback;
		}
	}

	private long parseLongOrDefault(String value, long fallback) {
		if (value == null) {
			return fallback;
		}
		try {
			return Long.parseLong(value.trim());
		} catch (NumberFormatException ignored) {
			return fallback;
		}
	}

	private void loadLegacyCredentialAsVoidscapeAccount() {
		String cred = ClientPort.loadCredentials();
		if (cred.length() <= 0) {
			return;
		}
		String[] split = cred.split(",", 2);
		if (split.length != 2 || split[0].trim().isEmpty() || split[1].isEmpty()) {
			return;
		}
		VoidscapeSavedAccount account = new VoidscapeSavedAccount();
		account.username = split[0].trim();
		account.password = split[1];
		account.displayName = account.username;
		account.combatLevel = 0;
		account.lastUsed = System.currentTimeMillis();
		this.voidscapeSavedAccounts.add(account);
		saveVoidscapeSavedAccounts();
	}

	private VoidscapeSavedAccount findVoidscapeSavedAccount(String username) {
		String key = voidscapeAccountKey(username);
		if (key.isEmpty()) {
			return null;
		}
		for (VoidscapeSavedAccount account : this.voidscapeSavedAccounts) {
			if (key.equals(voidscapeAccountKey(account.username))
				|| key.equals(voidscapeAccountKey(account.displayName))) {
				return account;
			}
		}
		return null;
	}

	private boolean saveVoidscapeCredentials(String username, String password, boolean markCurrent) {
		if (username == null || username.trim().isEmpty() || password == null || password.isEmpty()) {
			return false;
		}
		ensureVoidscapeSavedAccountsLoaded();
		if (usesSecureCredentialStore() && !this.voidscapeSavedAccountsLoaded) {
			return false;
		}
		CredentialSnapshot previousSnapshot = usesSecureCredentialStore()
			? credentialSnapshotFromMemory()
			: null;
		String cleanUser = username.trim();
		VoidscapeSavedAccount account = findVoidscapeSavedAccount(cleanUser);
		if (account == null) {
			if (this.voidscapeSavedAccounts.size() >= VOIDSCAPE_ACCOUNT_MAX) {
				return false;
			}
			account = new VoidscapeSavedAccount();
			this.voidscapeSavedAccounts.add(account);
		}
		account.username = cleanUser;
		account.password = password;
		if (account.displayName == null || account.displayName.trim().isEmpty()) {
			account.displayName = cleanUser;
		}
		if (markCurrent) {
			account.lastUsed = System.currentTimeMillis();
			if (usesSecureCredentialStore()) {
				this.voidscapeSelectedCredentialUsername = cleanUser;
			} else {
				ClientPort.saveCredentials(cleanUser + "," + password);
			}
		}
		sortVoidscapeSavedAccounts();
		boolean saved = saveVoidscapeSavedAccounts();
		if (!saved && previousSnapshot != null) {
			applyCredentialSnapshot(previousSnapshot);
		}
		return saved;
	}

	private boolean saveVoidscapeSavedAccounts() {
		if (usesSecureCredentialStore()) {
			if (!this.voidscapeSavedAccountsLoaded) {
				return false;
			}
			CredentialSnapshot snapshot = credentialSnapshotFromMemory();
			CredentialStore.Result result = credentialStore().replace(snapshot);
			if (result.getState() == CredentialStore.State.UNAVAILABLE) {
				return false;
			}
			applyCredentialSnapshot(result.hasValue()
				? result.getValue()
				: CredentialSnapshot.empty());
			return true;
		}

		Properties props = new Properties();
		int count = Math.min(this.voidscapeSavedAccounts.size(), VOIDSCAPE_ACCOUNT_MAX);
		props.setProperty("count", Integer.toString(count));
		for (int i = 0; i < count; i++) {
			VoidscapeSavedAccount account = this.voidscapeSavedAccounts.get(i);
			props.setProperty("account." + i + ".username", account.username == null ? "" : account.username);
			props.setProperty("account." + i + ".password", account.password == null ? "" : account.password);
			props.setProperty("account." + i + ".displayName", voidscapeAccountDisplayName(account));
			props.setProperty("account." + i + ".combatLevel", Integer.toString(Math.max(0, account.combatLevel)));
			props.setProperty("account." + i + ".lastUsed", Long.toString(Math.max(0L, account.lastUsed)));
		}
		File file = voidscapeAccountsFile();
		File parent = file.getParentFile();
		if (parent != null && !parent.isDirectory() && !parent.mkdirs()) {
			return false;
		}
		try (FileOutputStream out = new FileOutputStream(file)) {
			props.store(out, "Voidscape saved accounts");
			return true;
		} catch (IOException ignored) {
			return false;
		}
	}

	private CredentialSnapshot credentialSnapshotFromMemory() {
		ArrayList<SavedCredentialAccount> accounts = new ArrayList<>();
		int count = Math.min(this.voidscapeSavedAccounts.size(), VOIDSCAPE_ACCOUNT_MAX);
		for (int i = 0; i < count; i++) {
			VoidscapeSavedAccount account = this.voidscapeSavedAccounts.get(i);
			if (account.username == null || account.username.trim().isEmpty()
				|| account.password == null || account.password.isEmpty()) {
				continue;
			}
			accounts.add(new SavedCredentialAccount(
				account.username.trim(),
				account.password,
				voidscapeAccountDisplayName(account),
				Math.max(0, account.combatLevel),
				Math.max(0L, account.lastUsed)));
		}
		String selected = this.voidscapeSelectedCredentialUsername == null
			|| this.voidscapeSelectedCredentialUsername.trim().isEmpty()
			? null
			: this.voidscapeSelectedCredentialUsername.trim();
		return new CredentialSnapshot(selected, accounts);
	}

	private void sortVoidscapeSavedAccounts() {
		this.voidscapeSavedAccounts.sort((a, b) -> Long.compare(b.lastUsed, a.lastUsed));
	}

	private boolean removeVoidscapeSavedAccount(VoidscapeSavedAccount account) {
		if (account == null) {
			return false;
		}
		if (usesSecureCredentialStore()) {
			boolean current = isCurrentVoidscapeAccount(account);
			CredentialStore.Result result = credentialStore().forget(account.username);
			if (result.getState() == CredentialStore.State.UNAVAILABLE) {
				return false;
			}
			account.password = "";
			applyCredentialSnapshot(result.hasValue()
				? result.getValue()
				: CredentialSnapshot.empty());
			this.voidscapeSavedAccountsLoaded = true;
			if (current) {
				this.voidscapeRememberLoginRequested = false;
			}
			return true;
		}
		if (isCurrentVoidscapeAccount(account)) {
			return false;
		}
		boolean removed = this.voidscapeSavedAccounts.remove(account);
		if (!removed) {
			return false;
		}
		String removedKey = voidscapeAccountKey(account.username);
		String cred = ClientPort.loadCredentials();
		String[] split = cred.split(",", 2);
		if (split.length == 2 && removedKey.equals(voidscapeAccountKey(split[0]))
			&& getUsername() != null && !getUsername().trim().isEmpty()
			&& this.password != null && !this.password.isEmpty()) {
			ClientPort.saveCredentials(getUsername().trim() + "," + this.password);
		}
		saveVoidscapeSavedAccounts();
		return true;
	}

	private void noteVoidscapeLoginSucceeded(String username, String password, boolean reconnecting) {
		ensureVoidscapeSavedAccountsLoaded();
		VoidscapeSavedAccount existing = findVoidscapeSavedAccount(username);
		boolean credentialMutationCommitted = true;
		if (usesSecureCredentialStore()) {
			if (!reconnecting) {
				if (this.voidscapeAddAccountPending
					|| (this.voidscapeRememberLoginDecisionPending && this.voidscapeRememberLoginRequested)
					|| (!this.voidscapeRememberLoginDecisionPending && existing != null)) {
					credentialMutationCommitted = saveVoidscapeCredentials(username, password, true);
				} else if (this.voidscapeRememberLoginDecisionPending && existing != null) {
					credentialMutationCommitted = removeVoidscapeSavedAccount(existing);
				}
			}
		} else {
			boolean shouldRemember = this.voidscapeAddAccountPending
				|| existing != null
				|| this.voidscapeSavedAccounts.isEmpty();
			if (shouldRemember) {
				saveVoidscapeCredentials(username, password, true);
			}
		}
		if (credentialMutationCommitted) {
			this.voidscapeRememberLoginRequested = false;
			this.voidscapeRememberLoginDecisionPending = false;
		} else {
			this.showMessage(false, null, "Saved login unchanged - storage unavailable",
				MessageType.GAME, 0, null, "@red@");
		}
		this.voidscapeAddAccountPending = false;
		this.voidscapeOpenExistingLoginAfterLogout = false;
	}

	private int currentVoidscapeCombatLevel() {
		return this.localPlayer == null ? 0 : Math.max(0, this.localPlayer.level);
	}

	private void refreshVoidscapeCurrentAccountCache() {
		if (this.currentViewMode != GameMode.GAME || this.localPlayer == null) {
			return;
		}
		ensureVoidscapeSavedAccountsLoaded();
		String activeUser = getUsername();
		if (activeUser == null || activeUser.trim().isEmpty()) {
			activeUser = this.localPlayer.accountName;
		}
		VoidscapeSavedAccount account = findVoidscapeSavedAccount(activeUser);
		if (!usesSecureCredentialStore() && account == null && this.voidscapeSavedAccounts.isEmpty()
			&& activeUser != null && !activeUser.trim().isEmpty() && this.password != null && !this.password.isEmpty()) {
			saveVoidscapeCredentials(activeUser, this.password, true);
			account = findVoidscapeSavedAccount(activeUser);
		}
		if (account == null) {
			return;
		}
		String display = this.localPlayer.displayName != null && !this.localPlayer.displayName.trim().isEmpty()
			? this.localPlayer.displayName : this.localPlayer.accountName;
		int combatLevel = currentVoidscapeCombatLevel();
		boolean changed = false;
		if (display != null && !display.trim().isEmpty()
			&& !display.trim().equals(account.displayName)) {
			account.displayName = display.trim();
			changed = true;
		}
		if (combatLevel > 0 && combatLevel != account.combatLevel) {
			account.combatLevel = combatLevel;
			changed = true;
		}
		if (changed && System.currentTimeMillis() - this.voidscapeLastAccountStatsWrite > VOIDSCAPE_ACCOUNT_STATS_SAVE_INTERVAL_MS) {
			this.voidscapeLastAccountStatsWrite = System.currentTimeMillis();
			saveVoidscapeSavedAccounts();
		}
	}

	private void startVoidscapeAccountSwitch(VoidscapeSavedAccount account) {
		if (account == null || account.username == null || account.password == null
			|| account.username.trim().isEmpty() || account.password.isEmpty()) {
			return;
		}
		String activeKey = voidscapeAccountKey(getUsername());
		String selectedKey = voidscapeAccountKey(account.username);
		if (!activeKey.isEmpty() && activeKey.equals(selectedKey)) {
			this.voidscapeAccountMenuOpen = false;
			return;
		}
		if (this.combatTimeout > 0) {
			this.showMessage(false, null, "You can't switch accounts right after combat",
				MessageType.GAME, 0, null, "@cya@");
			return;
		}
		String nextUsername = account.username;
		String nextPassword = account.password;
		CredentialSnapshot previousSnapshot = usesSecureCredentialStore()
			? credentialSnapshotFromMemory()
			: null;
		account.lastUsed = System.currentTimeMillis();
		if (usesSecureCredentialStore()) {
			this.voidscapeSelectedCredentialUsername = nextUsername;
		} else if (!ClientPort.saveCredentials(nextUsername + "," + nextPassword)) {
			this.showMessage(false, null, "Unable to save account switch",
				MessageType.GAME, 0, null, "@red@");
			return;
		}
		sortVoidscapeSavedAccounts();
		if (!saveVoidscapeSavedAccounts()) {
			if (previousSnapshot != null) {
				applyCredentialSnapshot(previousSnapshot);
			}
			this.showMessage(false, null, "Unable to save account switch",
				MessageType.GAME, 0, null, "@red@");
			return;
		}
		this.voidscapePendingSwitchUsername = nextUsername;
		this.voidscapePendingSwitchPassword = nextPassword;
		this.voidscapeAccountMenuOpen = false;
		this.showUiTab = 0;
		sendLogout(0);
	}

	private void startVoidscapeAddAccount() {
		ensureVoidscapeSavedAccountsLoaded();
		if (this.voidscapeSavedAccounts.size() >= VOIDSCAPE_ACCOUNT_MAX) {
			this.voidscapeAccountAddStatus = "Remove an account first";
			return;
		}
		this.voidscapeAddAccountPending = false;
		this.voidscapeOpenExistingLoginAfterLogout = false;
		this.voidscapeAccountDrawerCollapsed = false;
		this.voidscapeAccountAddFormOpen = true;
		this.voidscapeAccountMenuOpen = true;
		this.showUiTab = 0;
		ensureVoidscapeAccountAddPanel();
		this.voidscapeAccountAddPanel.setText(this.voidscapeAccountAddUser, "");
		this.voidscapeAccountAddPanel.setText(this.voidscapeAccountAddPass, "");
		this.voidscapeAccountAddPanel.setFocus(this.voidscapeAccountAddUser);
		this.voidscapeAccountAddStatus = "";
		clearVoidscapeAccountValidation();
	}

	private void closeVoidscapeAccountAddForm() {
		this.voidscapeAccountAddFormOpen = false;
		this.voidscapeAccountAddStatus = "";
		clearVoidscapeAccountValidation();
	}

	private void clearVoidscapeAccountValidation() {
		this.voidscapeAccountAddChecking = false;
		this.voidscapeAccountAddPendingUser = "";
		this.voidscapeAccountAddPendingPass = "";
		this.voidscapeAccountAddStartedAt = 0L;
	}

	private void expireVoidscapeAccountValidation() {
		if (!this.voidscapeAccountAddChecking) {
			return;
		}
		long startedAt = this.voidscapeAccountAddStartedAt;
		if (startedAt > 0L && System.currentTimeMillis() - startedAt >= VOIDSCAPE_ACCOUNT_VALIDATE_TIMEOUT_MS) {
			clearVoidscapeAccountValidation();
			this.voidscapeAccountAddStatus = "Unable to verify account";
		}
	}

	private void ensureVoidscapeAccountAddPanel() {
		int x = voidscapeAccountPanelX();
		int y = voidscapeAccountPanelY();
		int width = voidscapeAccountPanelWidth();
		if (this.voidscapeAccountAddPanel != null
			&& this.voidscapeAccountAddPanelX == x
			&& this.voidscapeAccountAddPanelY == y
			&& this.voidscapeAccountAddPanelWidth == width) {
			return;
		}
		String user = this.voidscapeAccountAddPanel == null || this.voidscapeAccountAddUser < 0
			? "" : this.voidscapeAccountAddPanel.getControlText(this.voidscapeAccountAddUser);
		String pass = this.voidscapeAccountAddPanel == null || this.voidscapeAccountAddPass < 0
			? "" : this.voidscapeAccountAddPanel.getControlText(this.voidscapeAccountAddPass);
		int cx = x + width / 2;
		this.voidscapeAccountAddPanel = new Panel(this.getSurface(), 8);
		this.voidscapeAccountAddUser = this.voidscapeAccountAddPanel.addCenteredTextEntry(cx,
			voidscapeAccountAddUserY(), voidscapeAccountAddFieldWidth(), 20, 22, 1, false, true);
		this.voidscapeAccountAddPass = this.voidscapeAccountAddPanel.addCenteredTextEntry(cx,
			voidscapeAccountAddPassY(), voidscapeAccountAddFieldWidth(), 20, 22, 1, true, true);
		this.voidscapeAccountAddSave = this.voidscapeAccountAddPanel.addButton(cx - 45,
			voidscapeAccountAddActionY(), 80, 26);
		this.voidscapeAccountAddCancel = this.voidscapeAccountAddPanel.addButton(cx + 45,
			voidscapeAccountAddActionY(), 80, 26);
		this.voidscapeAccountAddPanel.setText(this.voidscapeAccountAddUser, user == null ? "" : user);
		this.voidscapeAccountAddPanel.setText(this.voidscapeAccountAddPass, pass == null ? "" : pass);
		this.voidscapeAccountAddPanel.setFocus(this.voidscapeAccountAddUser);
		this.voidscapeAccountAddPanelX = x;
		this.voidscapeAccountAddPanelY = y;
		this.voidscapeAccountAddPanelWidth = width;
	}

	private void saveVoidscapeAccountAddForm() {
		if (this.voidscapeAccountAddChecking) {
			return;
		}
		ensureVoidscapeAccountAddPanel();
		String user = this.voidscapeAccountAddPanel.getControlText(this.voidscapeAccountAddUser);
		String pass = this.voidscapeAccountAddPanel.getControlText(this.voidscapeAccountAddPass);
		if (user == null || user.trim().isEmpty() || pass == null || pass.isEmpty()) {
			this.voidscapeAccountAddStatus = "Enter username and password";
			return;
		}
		ensureVoidscapeSavedAccountsLoaded();
		VoidscapeSavedAccount existing = findVoidscapeSavedAccount(user);
		if (existing == null && this.voidscapeSavedAccounts.size() >= VOIDSCAPE_ACCOUNT_MAX) {
			this.voidscapeAccountAddStatus = "Remove an account first";
			return;
		}
		if (isCurrentVoidscapeAccount(existing)) {
			this.voidscapeAccountAddStatus = "Current account already saved";
			return;
		}
		if (this.packetHandler == null || this.packetHandler.getClientStream() == null) {
			this.voidscapeAccountAddStatus = "Unable to verify account";
			return;
		}
		this.voidscapeAccountAddStatus = "Checking account...";
		this.voidscapeAccountAddChecking = true;
		this.voidscapeAccountAddPendingUser = user.trim();
		this.voidscapeAccountAddPendingPass = pass;
		this.voidscapeAccountAddStartedAt = System.currentTimeMillis();
		try {
			this.packetHandler.getClientStream().newPacket(199);
			this.packetHandler.getClientStream().bufferBits.putByte(15);
			this.packetHandler.getClientStream().bufferBits.putString(user.trim());
			this.packetHandler.getClientStream().bufferBits.putString(pass);
			this.packetHandler.getClientStream().finishPacketAndFlush();
		} catch (Exception ignored) {
			clearVoidscapeAccountValidation();
			this.voidscapeAccountAddStatus = "Unable to verify account";
		}
	}

	final boolean handleVoidscapeAccountAuthMessage(String message) {
		if (message == null || !message.startsWith(VOIDSCAPE_ACCOUNT_AUTH_PREFIX)) {
			return false;
		}
		String[] parts = message.substring(VOIDSCAPE_ACCOUNT_AUTH_PREFIX.length()).split("\\|", 4);
		if (parts.length < 3 || !this.voidscapeAccountAddChecking) {
			return true;
		}
		String user = parts[1] == null ? "" : parts[1].trim();
		if (!voidscapeAccountKey(user).equals(voidscapeAccountKey(this.voidscapeAccountAddPendingUser))) {
			return true;
		}
		boolean success = "1".equals(parts[0]);
		int combatLevel = parseIntOrDefault(parts[2], 0);
		String detail = parts.length >= 4 ? parts[3].trim() : "";
		String pendingUser = this.voidscapeAccountAddPendingUser;
		String pendingPass = this.voidscapeAccountAddPendingPass;
		clearVoidscapeAccountValidation();
		if (!success) {
			this.voidscapeAccountAddStatus = detail.isEmpty() ? "Invalid username or password" : detail;
			return true;
		}
		ensureVoidscapeSavedAccountsLoaded();
		if (findVoidscapeSavedAccount(pendingUser) == null && this.voidscapeSavedAccounts.size() >= VOIDSCAPE_ACCOUNT_MAX) {
			this.voidscapeAccountAddStatus = "Remove an account first";
			return true;
		}
		if (!saveVoidscapeCredentials(user.isEmpty() ? pendingUser : user, pendingPass, false)) {
			this.voidscapeAccountAddStatus = "Unable to save account";
			return true;
		}
		VoidscapeSavedAccount account = findVoidscapeSavedAccount(user.isEmpty() ? pendingUser : user);
		if (account != null && combatLevel > 0 && account.combatLevel != combatLevel) {
			account.combatLevel = combatLevel;
			saveVoidscapeSavedAccounts();
		}
		this.voidscapeAccountAddFormOpen = false;
		this.voidscapeAccountMenuOpen = true;
		this.voidscapeAccountAddStatus = "";
		return true;
	}

	final boolean handleVoidscapeFarmSimMessage(String message) {
		if (message == null || !message.startsWith(VOIDSCAPE_FARMSIM_PREFIX)) {
			return false;
		}
		String payload = message.substring(VOIDSCAPE_FARMSIM_PREFIX.length());
		String[] parts = payload.split("\\|", 5);
		if (parts.length < 5 || !"v1".equals(parts[0])) {
			return true;
		}
		this.farmSimTitle = parts[1];
		this.farmSimSubtitle = parts[2];
		this.farmSimDetails = parts[3];
		this.farmSimItems.clear();
		if (parts[4] != null && parts[4].length() > 0) {
			String[] items = parts[4].split(";");
			for (String item : items) {
				String[] pair = item.split(",", 2);
				if (pair.length != 2) {
					continue;
				}
				int itemId = parseIntOrDefault(pair[0], -1);
				long amount = parseLongOrDefault(pair[1], 0L);
				if (itemId >= 0 && itemId < EntityHandler.itemCount() && amount > 0L) {
					this.farmSimItems.add(new FarmSimItem(itemId, amount));
				}
			}
		}
		this.farmSimScrollPixels = 0;
		this.showDialogFarmSim = true;
		this.mouseButtonClick = 0;
		return true;
	}

	final boolean handleUndeadSiegeMessage(String message) {
		if (message == null || !message.startsWith(VOIDSCAPE_UNDEAD_SIEGE_PREFIX)) {
			return false;
		}
		String payload = message.substring(VOIDSCAPE_UNDEAD_SIEGE_PREFIX.length());
		if (payload.startsWith("points|")) {
			this.undeadSiegeShopPoints = Math.max(0, parseIntOrDefault(payload.substring("points|".length()), 0));
		}
		return true;
	}

	final boolean handleVoidArenaRatingMessage(String message) {
		if (message == null || !message.startsWith(VOIDSCAPE_ARENA_PREFIX)) {
			return false;
		}
		String payload = message.substring(VOIDSCAPE_ARENA_PREFIX.length());
		if ("clear".equals(payload)) {
			this.voidArenaRatingsByName.clear();
			this.voidArenaRankedEligibleByName.clear();
			this.voidArenaDmKingWins = -1;
			this.voidArenaDmKingLosses = -1;
			this.showDialogVoidArenaDeathMatch = false;
			this.voidArenaCountdownEndMillis = 0L;
			return true;
		}
		if ("close".equals(payload)) {
			this.showDialogVoidArenaDeathMatch = false;
			this.voidArenaDeathMatchTargetIndex = -1;
			this.voidArenaCountdownEndMillis = 0L;
			this.voidArenaDeathMatchConfirmPhase = false;
			this.voidArenaDeathMatchAccepted = false;
			this.voidArenaDeathMatchOpponentAccepted = false;
			this.voidArenaDeathMatchConfirmed = false;
			this.voidArenaDeathMatchOpponentConfirmed = false;
			return true;
		}
		String[] parts = payload.split("\\|", 11);
		if (parts.length >= 2 && "countdown".equals(parts[0])) {
			int seconds = Math.max(1, parseIntOrDefault(parts[1], 5));
			this.voidArenaCountdownEndMillis = System.currentTimeMillis() + seconds * 1000L;
			return true;
		}
		if (parts.length >= 10 && "setup".equals(parts[0])) {
			this.voidArenaDeathMatchTargetIndex = parseIntOrDefault(parts[1], -1);
			this.voidArenaDeathMatchTargetName = parts[2];
			this.voidArenaDeathMatchTargetKey = StringUtil.displayNameToKey(parts[2]);
			applyVoidArenaDeathMatchRuleMask(parseIntOrDefault(parts[3], 0));
			this.voidArenaDeathMatchAccepted = "1".equals(parts[4]);
			this.voidArenaDeathMatchOpponentAccepted = "1".equals(parts[5]);
			this.voidArenaDeathMatchConfirmPhase = "1".equals(parts[6]);
			this.voidArenaDeathMatchConfirmed = "1".equals(parts[7]);
			this.voidArenaDeathMatchOpponentConfirmed = "1".equals(parts[8]);
			this.voidArenaDeathMatchRankedAvailable = "1".equals(parts[9]);
			this.showDialogVoidArenaDeathMatch = true;
			this.mouseButtonClick = 0;
			return true;
		}
		if (parts.length >= 3 && "dmking".equals(parts[0])) {
			int wins = parseIntOrDefault(parts[1], -1);
			int losses = parseIntOrDefault(parts[2], -1);
			if (wins >= 0 && losses >= 0) {
				this.voidArenaDmKingWins = wins;
				this.voidArenaDmKingLosses = losses;
			}
			return true;
		}
		if (parts.length < 5 || !"rating".equals(parts[0])) {
			return true;
		}
		String key = StringUtil.displayNameToKey(parts[1]);
		if (key == null) {
			return true;
		}
		if (parts.length >= 6) {
			this.voidArenaRankedEligibleByName.put(key, "1".equals(parts[5]));
		}
		if (!"1".equals(parts[4])) {
			this.voidArenaRatingsByName.put(key, -1);
			return true;
		}
		int rating = parseIntOrDefault(parts[2], -1);
		if (rating > 0) {
			this.voidArenaRatingsByName.put(key, rating);
		} else {
			this.voidArenaRatingsByName.remove(key);
		}
		return true;
	}

	private void openVoidscapeAddAccountLogin() {
		this.loginScreenNumber = 2;
		this.voidscapeOpenExistingLoginAfterLogout = false;
		if (this.panelLogin != null) {
			this.panelLogin.setText(this.controlLoginUser, "");
			this.panelLogin.setText(this.controlLoginPass, "");
			this.panelLogin.setFocus(this.controlLoginUser);
		}
		this.setUsername("");
		this.password = "";
		showLoginScreenStatus("Add another account", "Log in once to save it");
	}

	private void completeVoidscapePendingAccountSwitch() {
		if (this.voidscapePendingSwitchUsername == null || this.voidscapePendingSwitchUsername.trim().isEmpty()
			|| this.voidscapePendingSwitchPassword == null || this.voidscapePendingSwitchPassword.isEmpty()) {
			if (this.voidscapeOpenExistingLoginAfterLogout) {
				openVoidscapeAddAccountLogin();
			}
			return;
		}
		String nextUser = this.voidscapePendingSwitchUsername;
		String nextPass = this.voidscapePendingSwitchPassword;
		this.voidscapePendingSwitchUsername = "";
		this.voidscapePendingSwitchPassword = "";
		this.loginScreenNumber = 2;
		if (this.panelLogin != null) {
			this.panelLogin.setText(this.controlLoginUser, nextUser);
			this.panelLogin.setText(this.controlLoginPass, nextPass);
		}
		this.setUsername(nextUser);
		this.password = nextPass;
		this.autoLoginTimeout = 2;
		this.login(-12, nextPass, nextUser, false);
	}

	public boolean webSmokeLogin(String user, String pass) {
		if (!Config.isWeb() || this.currentViewMode != GameMode.LOGIN || user == null || pass == null) {
			return false;
		}
		String cleanUser = user.trim();
		if (cleanUser.length() == 0 || pass.length() == 0) {
			return false;
		}
		this.loginScreenNumber = 2;
		if (this.panelLogin != null) {
			this.panelLogin.setText(this.controlLoginUser, cleanUser);
			this.panelLogin.setText(this.controlLoginPass, pass);
			this.panelLogin.setFocus(this.controlLoginPass);
		}
		this.setUsername(cleanUser);
		this.password = pass;
		this.autoLoginTimeout = 2;
		this.login(-12, pass, cleanUser, false);
		return true;
	}

