	private int getExperienceCounterColor() {
		switch (C_EXPERIENCE_COUNTER_COLOR) {
			case 1:
				return 0xFFFF00; // Yellow
			case 2:
				return 0xFF0000; // Red
			case 3:
				return 0x0000FF; // Blue
			case 4:
				return 0x00FF00; // Green
			case 5:
				return 0xFF8ED9; // Pink
			case 6:
				return 0xFF00FF; // Magenta
			default:
				return 0xFFFFFF; // White
		}
	}

	public void noteSkillExperienceGain(int skill, int receivedXp) {
		if (receivedXp <= 0 || !isValidSkillIndex(skill)) {
			return;
		}
		long now = System.currentTimeMillis();
		if (isPrimaryCombatTrainingSkill(skill)) {
			this.trainingXpRateLastPrimaryCombatSkill = skill;
			this.trainingXpRateLastPrimaryCombatGainMillis = now;
			this.trainingXpRateSkill = skill;
		} else if (skill == SKILL_HITS
			&& this.trainingXpRateLastPrimaryCombatSkill >= 0
			&& now - this.trainingXpRateLastPrimaryCombatGainMillis <= TRAINING_XP_RATE_HITS_SUPPRESS_MILLIS) {
			this.trainingXpRateSkill = this.trainingXpRateLastPrimaryCombatSkill;
		} else {
			this.trainingXpRateSkill = skill;
		}
		this.trainingXpRateLastGainMillis = now;
		this.trainingXpRateLastRefreshMillis = 0L;
	}

	private boolean isValidSkillIndex(int skill) {
		return skill >= 0 && skill < skillCount
			&& this.playerStatXpGained != null && skill < this.playerStatXpGained.length
			&& this.xpGainedStartTime != null && skill < this.xpGainedStartTime.length;
	}

	private boolean isPrimaryCombatTrainingSkill(int skill) {
		return skill == SKILL_ATTACK || skill == SKILL_DEFENSE || skill == SKILL_STRENGTH
			|| skill == SKILL_RANGED || skill == SKILL_MAGIC;
	}

	private void drawTrainingXpRateBadge() {
		if (useVoidscapeHudSkin()
			&& (this.showUiTab != 0 || this.voidscapeAccountMenuOpen || this.voidscapeAccountAddFormOpen)) {
			return;
		}
		if (!isValidSkillIndex(this.trainingXpRateSkill)) {
			return;
		}
		long now = System.currentTimeMillis();
		if (now - this.trainingXpRateLastGainMillis > TRAINING_XP_RATE_IDLE_MILLIS) {
			return;
		}
		long gained = Math.max(0L, this.playerStatXpGained[this.trainingXpRateSkill]);
		if (gained <= 0L) {
			return;
		}
		if (this.trainingXpRateLastRefreshMillis == 0L
			|| now - this.trainingXpRateLastRefreshMillis >= TRAINING_XP_RATE_REFRESH_MILLIS) {
			long elapsed = Math.max(1000L, now - this.xpGainedStartTime[this.trainingXpRateSkill]);
			this.trainingXpRateCachedPerHour = (gained * 3600000L) / elapsed;
			this.trainingXpRateLastRefreshMillis = now;
		}

		String skillName = skillNameLong != null && this.trainingXpRateSkill < skillNameLong.length
			? skillNameLong[this.trainingXpRateSkill] : "Skill";
		int font = 1;
		String label = skillName + " XP/hr: " + formatCompactLong(this.trainingXpRateCachedPerHour);
		int maxWidth = Math.max(110, Math.min(190, this.getGameWidth() - 16));
		int width = this.getSurface().stringWidth(font, label) + 14;
		if (width > maxWidth) {
			width = maxWidth;
			label = fitVoidscapeText(label, width - 12, font);
		}
		int height = useVoidscapeHudSkin() ? 22 : 20;
		int x = trainingXpRateBadgeX(width);
		int y = trainingXpRateBadgeY(height);

		if (useVoidscapeHudSkin()) {
			this.getSurface().drawBoxAlpha(x, y, width, height, UiSkin.VOID_BODY, 188);
			this.getSurface().drawBoxBorder(x, width, y, height, UiSkin.GOLD_BEVEL);
			this.getSurface().drawLineHoriz(x + 2, y + 1, Math.max(1, width - 4), UiSkin.GOLD_LINE);
			this.getSurface().drawString(label, x + 7, y + 15, UiSkin.TEXT_BODY, font);
		} else {
			this.getSurface().drawBoxAlpha(x, y, width, height, 0, 130);
			this.getSurface().drawBoxBorder(x, width, y, height, 0xFFFFFF);
			this.getSurface().drawString(label, x + 7, y + 14, 0xFFFF00, font);
		}
	}

	private int trainingXpRateBadgeX(int width) {
		int margin = useVoidscapeHudSkin() ? (voidscapeCompactHud() ? 8 : 10) : 8;
		return Math.max(8, this.getGameWidth() - width - margin);
	}

	private int trainingXpRateBadgeY(int height) {
		if (useVoidscapeHudSkin()) {
			int topClearance = VOIDSCAPE_TOP_TAB_Y + voidscapeTopTabSize() + (voidscapeCompactHud() ? 4 : 6);
			int y = voidscapeAccountButtonY() - height - (voidscapeCompactHud() ? 4 : 6);
			return Math.max(topClearance, y);
		}
		int bottomClearance = inWild ? 84 : 44;
		return Math.max(6, this.getGameHeight() - bottomClearance - height);
	}

	private void drawExperienceCounter(int skill) {
		if (!S_EXPERIENCE_COUNTER_TOGGLE) return;
		if (selectedSkill >= 0) {
			skill = selectedSkill;
		}
		int textColor = getExperienceCounterColor();
		// The counter and the training-rate badge show different data (running
		// totals + til-level vs live XP/hr), so both stay; under the void skin
		// the counter's chrome joins the badge palette (tokens). The text color
		// is the player's synced counter-color setting, not chrome, and is kept
		// in both skins. Classic grey backing stays byte-identical. Hit rects
		// derive from the same x/width as the boxes and are unchanged.
		boolean voidSkinCounter = useVoidscapeHudSkin();
		int counterBg = voidSkinCounter ? UiSkin.VOID_BODY : 0x989898;
		int counterBgAlpha = voidSkinCounter ? 188 : 90;
		long totalXp = 0;
		long timePassed = 0;
		if (C_EXPERIENCE_COUNTER_MODE == 1 || skill < 0) {
			for (int i = 0; i < skillCount; i++) {
				totalXp += this.playerExperience[i] & 0xffffffffL;
			}

			int stringWid = getSurface().stringWidth(3, "Total: " + totalXp);
			int x = halfGameWidth() - (stringWid / 2) - 10;
			int width = stringWid + 6;
			this.getSurface().drawBoxAlpha(x, 0, width, 20, counterBg, counterBgAlpha);
			//this.getSurface().drawBoxBorder(x, width, 0, 20, 0x000000);

			if (textColor == 0xFFFFFF) {
				getSurface().drawShadowText("Total: " + totalXp, halfGameWidth() - (stringWid / 2) - 4, 15, textColor, 2, false);
			} else {
				getSurface().drawString("Total: " + totalXp, halfGameWidth() - (stringWid / 2) - 4, 15, textColor, 2);
			}

			if (isAndroid() && this.mouseButtonClick == 1 && mouseX >= x && mouseX <= x + width && mouseY >= 0 && mouseY <= 20) {
				if (doubleClick()) {
					experienceConfigInterface.setVisible(true);
					setMouseClick(0);
				}
			} else if (!isAndroid() && this.mouseButtonClick == 1 && mouseX >= x && mouseX <= x + width && mouseY >= 0 && mouseY <= 20) {
				experienceConfigInterface.setVisible(true);
				setMouseClick(0);
			}

			if (C_EXPERIENCE_CONFIG_SUBMENU && mouseX >= x && mouseX <= x + width && mouseY >= 0 && mouseY <= 20) {
				// Checks for non-positive gains
				if (this.playerXpGainedTotal < 0) {
					this.playerXpGainedTotal = 0;
				}

				// Used to make sure it isn't changing so quickly
				xpPerHourCount++;
				if (xpPerHourCount % 100 == 0) {
					timePassed = System.currentTimeMillis() - this.totalXpGainedStartTime;
					xpPerHour = this.playerXpGainedTotal / (((double) timePassed) / 3600000);
				}
				this.getSurface().drawBoxAlpha(x, 19, width, 31, counterBg, counterBgAlpha);
				//this.getSurface().drawBoxBorder(x, width, 19, 31, 0x000000);

				if (textColor == 0xFFFFFF) {
					this.getSurface().drawShadowText("Gained: " + this.playerXpGainedTotal, x + 3, 31, textColor, 2, false);
					this.getSurface().drawShadowText("Xp/hr:     " + (int) xpPerHour, x + 3, 46, textColor, 2, false);
				} else {
					this.getSurface().drawString("Gained: " + this.playerXpGainedTotal, x + 3, 31, textColor, 2);
					this.getSurface().drawString("Xp/hr:     " + (int) xpPerHour, x + 3, 46, textColor, 2);
				}
			}
		} else {
			int stringWid = getSurface().stringWidth(3, skillNames[skill] + ": " + playerStatBase[skill] + ": " + playerExperience[skill]);
			int x = (getGameWidth() / 2) - (stringWid / 2) - 10;
			int width = stringWid + 6;
			this.getSurface().drawBoxAlpha(x, 0, width, 20, counterBg, counterBgAlpha);
			//this.getSurface().drawBoxBorder(x, width, 0, 20, 0x000000);

			int tilLvl = 0, baseTilLvl = 0, progressWidth = 0;
			double progress = 0;
			if (playerStatBase[skill] != S_PLAYER_LEVEL_LIMIT) {
				tilLvl = this.experienceArray[playerStatBase[skill] - 1] - this.playerExperience[skill];
				baseTilLvl = this.experienceArray[playerStatBase[skill]] - this.experienceArray[playerStatBase[skill] - 1];
				progress = ((double) tilLvl) / ((double) baseTilLvl) / 0.9;
				progressWidth = (int) (progress * width);

				this.getSurface().drawBox(x, 19, width - progressWidth, 2, voidSkinCounter ? UiSkin.GOOD : 0x00FF00);
				this.getSurface().drawBox(x + width - progressWidth, 19, progressWidth, 2, voidSkinCounter ? UiSkin.BAD : 0xFF0000);
			}

			if (textColor == 0xFFFFFF) {
				getSurface().drawShadowText(skillNames[skill] + ": " + playerStatBase[skill] + ": " + playerExperience[skill], (getGameWidth() / 2) - (stringWid / 2) - 4, 15, textColor, 2, false);
			} else {
				getSurface().drawString(skillNames[skill] + ": " + playerStatBase[skill] + ": " + playerExperience[skill], (getGameWidth() / 2) - (stringWid / 2) - 4, 15, textColor, 2);
			}

			if (isAndroid() && this.mouseButtonClick == 1 && mouseX >= x && mouseX <= x + width && mouseY >= 0 && mouseY <= 20) {
				if (doubleClick()) {
					experienceConfigInterface.setVisible(true);
					setMouseClick(0);
				}
			} else if (!isAndroid() && this.mouseButtonClick == 1 && mouseX >= x && mouseX <= x + width && mouseY >= 0 && mouseY <= 20) {
				experienceConfigInterface.setVisible(true);
				setMouseClick(0);
			}

			if (C_EXPERIENCE_CONFIG_SUBMENU && mouseX >= x && mouseX <= x + width && mouseY >= 0 && mouseY <= 20) {
				// Checks for non-positive gains
				if (this.playerStatXpGained[skill] < 0) {
					this.playerStatXpGained[skill] = 0;
				}

				// Used to make sure it isn't changing too quickly
				xpPerHourCount++;
				if (xpPerHourCount % 100 == 0) {
					timePassed = System.currentTimeMillis() - this.xpGainedStartTime[skill];
					xpPerHour = this.playerStatXpGained[skill] / (((double) timePassed) / 3600000);
				}
				this.getSurface().drawBoxAlpha(x, 20, width, 61, counterBg, counterBgAlpha);
				//this.getSurface().drawBoxBorder(x, width, 19, 61, 0x000000);

				if (textColor == 0xFFFFFF) {
					if (playerStatBase[skill] == S_PLAYER_LEVEL_LIMIT) {
						this.getSurface().drawShadowText("Gained: " + this.playerStatXpGained[skill], x + 3, 63, textColor, 2, false);
						this.getSurface().drawShadowText("Xp/hr:     " + (int) xpPerHour, x + 3, 78, textColor, 2, false);
					} else {
						this.getSurface().drawShadowText("Next lvl: " + this.experienceArray[playerStatBase[skill] - 1], x + 3, 33, textColor, 2, false);
						this.getSurface().drawShadowText("Til lvl:     " + tilLvl, x + 3, 48, textColor, 2, false);
						this.getSurface().drawShadowText("Gained: " + this.playerStatXpGained[skill], x + 3, 63, textColor, 2, false);
						this.getSurface().drawShadowText("Xp/hr:     " + (int) xpPerHour, x + 3, 78, textColor, 2, false);
					}
				} else {
					if (playerStatBase[skill] == S_PLAYER_LEVEL_LIMIT) {
						this.getSurface().drawString("Gained: " + this.playerStatXpGained[skill], x + 3, 63, textColor, 2);
						this.getSurface().drawString("Xp/hr:     " + (int) xpPerHour, x + 3, 78, textColor, 2);
					} else {
						this.getSurface().drawString("Next lvl: " + this.experienceArray[playerStatBase[skill] - 1], x + 3, 33, textColor, 2);
						this.getSurface().drawString("Til lvl:     " + tilLvl, x + 3, 48, textColor, 2);
						this.getSurface().drawString("Gained: " + this.playerStatXpGained[skill], x + 3, 63, textColor, 2);
						this.getSurface().drawString("Xp/hr:     " + (int) xpPerHour, x + 3, 78, textColor, 2);
					}
				}
			}
		}
	}

