	private int voidscapeDebugIntProperty(String propertyName, int defaultValue, int min, int max) {
		String raw = System.getProperty(propertyName);
		if (raw == null || raw.trim().isEmpty()) {
			return defaultValue;
		}
		try {
			int value = Integer.parseInt(raw.trim());
			return Math.max(min, Math.min(max, value));
		} catch (NumberFormatException ignored) {
			return defaultValue;
		}
	}

	private int voidscapeDebugColorProperty(String propertyName, int defaultValue) {
		String raw = System.getProperty(propertyName);
		if (raw == null || raw.trim().isEmpty()) {
			return defaultValue;
		}
		String normalized = raw.trim();
		if (normalized.startsWith("#")) {
			normalized = normalized.substring(1);
		} else if (normalized.startsWith("0x") || normalized.startsWith("0X")) {
			normalized = normalized.substring(2);
		}
		try {
			return (int) (Long.parseLong(normalized, 16) & 0xFFFFFFL);
		} catch (NumberFormatException ignored) {
			return defaultValue;
		}
	}

	private void ensureVoidscapeUiSkinLoaded() {
		if (this.voidscapeUiSkinLoadAttempted) {
			return;
		}
		this.voidscapeUiSkinLoadAttempted = true;
		File skinDir = new File(Config.F_CACHE_DIR,
			"voidscape" + File.separator + "ui" + File.separator + "skin");
		Set<String> assets = new LinkedHashSet<>(Arrays.asList(VOIDSCAPE_SKIN_ASSETS));
		File[] discoveredAssets = skinDir.listFiles((dir, name) ->
			name.toLowerCase(Locale.ROOT).endsWith(".png"));
		if (discoveredAssets != null) {
			for (File assetFile : discoveredAssets) {
				assets.add(assetFile.getName());
			}
		}
		for (String asset : assets) {
			loadVoidscapeSkinSprite(skinDir, asset);
		}
	}

	private Sprite getVoidscapeSkinSprite(String asset) {
		ensureVoidscapeUiSkinLoaded();
		Sprite sprite = this.voidscapeUiSkinSprites.get(asset);
		if (sprite != null || this.voidscapeUiSkinMissing.contains(asset)) {
			return sprite;
		}
		File skinDir = new File(Config.F_CACHE_DIR,
			"voidscape" + File.separator + "ui" + File.separator + "skin");
		return loadVoidscapeSkinSprite(skinDir, asset);
	}

	private Sprite loadVoidscapeSkinSprite(File skinDir, String asset) {
		File assetFile = new File(skinDir, asset);
		Sprite sprite = PngSpriteLoader.readArgb(assetFile);
		if (sprite == null) {
			sprite = readPngSpriteWithClientPort(assetFile);
		}
		if (sprite != null) {
			this.voidscapeUiSkinSprites.put(asset, sprite);
			return sprite;
		}
		this.voidscapeUiSkinMissing.add(asset);
		return null;
	}

	private String voidscapeSizedSkinAsset(String asset, int size) {
		int dot = asset.lastIndexOf('.');
		if (dot <= 0) {
			return asset;
		}
		if (!voidscapeHasSizedSkinAssetFamily(asset)) {
			return asset;
		}
		size = voidscapeNearestKnownSkinAssetSize(asset, size);
		String sizedAsset = asset.substring(0, dot) + "-" + size + asset.substring(dot);
		return getVoidscapeSkinSprite(sizedAsset) != null ? sizedAsset : asset;
	}

	private boolean voidscapeHasSizedSkinAssetFamily(String asset) {
		return asset.startsWith("top-bag")
			|| asset.startsWith("top-book")
			|| asset.startsWith("top-gear")
			|| asset.startsWith("top-map-scroll")
			|| asset.startsWith("top-social-smiley")
			|| asset.startsWith("top-stats-bars")
			|| asset.startsWith("bottom-account-manager")
			|| asset.startsWith("bottom-chat-")
			|| asset.startsWith("quest-star")
			|| asset.startsWith("private-heads")
			|| asset.startsWith("skill-")
			|| asset.startsWith("equip-")
			|| asset.startsWith("bank-chest")
			|| asset.startsWith("bank-deposit-arrow")
			|| asset.startsWith("bank-loadouts-shirt")
			|| asset.startsWith("bank-search");
	}

	private int voidscapeNearestKnownSkinAssetSize(String asset, int size) {
		if (asset.startsWith("top-bag")
			|| asset.startsWith("top-book")
			|| asset.startsWith("top-gear")
			|| asset.startsWith("top-map-scroll")
			|| asset.startsWith("top-social-smiley")
			|| asset.startsWith("top-stats-bars")) {
			return nearestAssetSize(VOIDSCAPE_TOP_ICON_SIZES, size);
		}
		if (asset.startsWith("bottom-account-manager")) {
			return nearestAssetSize(VOIDSCAPE_ACCOUNT_ICON_SIZES, size);
		}
		if (asset.startsWith("bottom-chat-")) {
			return nearestAssetSize(VOIDSCAPE_BOTTOM_CHAT_ICON_SIZES, size);
		}
		if (asset.startsWith("quest-star") || asset.startsWith("private-heads")) {
			return nearestAssetSize(VOIDSCAPE_PANEL_ICON_SIZES, size);
		}
		if (asset.startsWith("skill-")) {
			return nearestAssetSize(VOIDSCAPE_SKILL_ICON_SIZES, size);
		}
		if (asset.startsWith("bank-chest")
			|| asset.startsWith("bank-deposit-arrow")
			|| asset.startsWith("bank-loadouts-shirt")
			|| asset.startsWith("bank-search")) {
			return nearestAssetSize(VOIDSCAPE_BANK_ICON_SIZES, size);
		}
		return size;
	}

	private static int nearestAssetSize(int[] sizes, int target) {
		int best = sizes[0];
		int bestDistance = Math.abs(target - best);
		for (int i = 1; i < sizes.length; i++) {
			int distance = Math.abs(target - sizes[i]);
			if (distance < bestDistance || distance == bestDistance && sizes[i] > best) {
				best = sizes[i];
				bestDistance = distance;
			}
		}
		return best;
	}

	private String voidscapeSkinAssetOrDefault(String preferredAsset, String fallbackAsset) {
		return getVoidscapeSkinSprite(preferredAsset) != null ? preferredAsset : fallbackAsset;
	}

	private void drawVoidscapeSkinSprite(String asset, int x, int y, int width, int height) {
		Sprite sprite = getVoidscapeSkinSprite(asset);
		if (sprite != null) {
			this.getSurface().drawArgbSpriteClipping(sprite, x, y, width, height, false, 0, 0xFFFFFFFF);
		}
	}

	public void drawVoidscapeUiSkinSprite(String asset, int x, int y, int width, int height) {
		drawVoidscapeSkinSprite(asset, x, y, width, height);
	}

	public String voidscapeSizedUiSkinAsset(String asset, int size) {
		return voidscapeSizedSkinAsset(asset, size);
	}

	private Sprite voidscapeSkinSlice(String asset, Sprite master, int sx, int sy, int sw, int sh) {
		String key = asset + ":" + sx + "," + sy + "," + sw + "," + sh;
		Sprite cached = this.voidscapeUiSkinSlices.get(key);
		if (cached != null) {
			return cached;
		}
		sx = Math.max(0, Math.min(sx, master.getWidth() - 1));
		sy = Math.max(0, Math.min(sy, master.getHeight() - 1));
		sw = Math.max(1, Math.min(sw, master.getWidth() - sx));
		sh = Math.max(1, Math.min(sh, master.getHeight() - sy));
		int[] out = new int[sw * sh];
		int[] src = master.getPixels();
		for (int row = 0; row < sh; row++) {
			System.arraycopy(src, (sy + row) * master.getWidth() + sx, out, row * sw, sw);
		}
		Sprite slice = new Sprite(out, sw, sh);
		this.voidscapeUiSkinSlices.put(key, slice);
		return slice;
	}

	private void drawVoidscapeSlice(String asset, Sprite master, int sx, int sy, int sw, int sh,
									int dx, int dy, int dw, int dh) {
		if (dw <= 0 || dh <= 0) {
			return;
		}
		Sprite slice = voidscapeSkinSlice(asset, master, sx, sy, sw, sh);
		this.getSurface().drawArgbSpriteClipping(slice, dx, dy, dw, dh, false, 0, 0xFFFFFFFF);
	}

	// Horizontal rail segment with an optional 1:1 center ornament (keeps gems undistorted while
	// the plain rail on either side stretches).
	private void drawVoidscapeSliceRailH(String asset, Sprite master, int srcX, int srcY, int srcW, int srcH,
										 int dx, int dy, int dw, int dh, int centerW) {
		if (centerW > 0 && centerW < srcW && centerW < dw) {
			int srcCenterX = srcX + (srcW - centerW) / 2;
			int dstCenterX = dx + (dw - centerW) / 2;
			drawVoidscapeSlice(asset, master, srcX, srcY, srcCenterX - srcX, srcH,
				dx, dy, dstCenterX - dx, dh);
			drawVoidscapeSlice(asset, master, srcCenterX, srcY, centerW, srcH,
				dstCenterX, dy, centerW, dh);
			int srcAfter = srcCenterX + centerW;
			int dstAfter = dstCenterX + centerW;
			drawVoidscapeSlice(asset, master, srcAfter, srcY, srcX + srcW - srcAfter, srcH,
				dstAfter, dy, dx + dw - dstAfter, dh);
		} else {
			drawVoidscapeSlice(asset, master, srcX, srcY, srcW, srcH, dx, dy, dw, dh);
		}
	}

	// Nine-slice frame draw: corners render 1:1, rails stretch along their axis only, interior is
	// left empty (panels paint their own fill). Fixes the pixelated/distorted look of stretching
	// one frame sprite to every panel size.
	private void drawVoidscapeNineSlice(String asset, int x, int y, int w, int h,
										int corner, int topCenterW, int bottomCenterW) {
		Sprite master = getVoidscapeSkinSprite(asset);
		if (master == null) {
			return;
		}
		int mw = master.getWidth();
		int mh = master.getHeight();
		int c = Math.min(corner, Math.min(Math.min(mw, mh) / 2 - 1, Math.min(w, h) / 2 - 1));
		if (c <= 0) {
			drawVoidscapeSkinSprite(asset, x, y, w, h);
			return;
		}
		// Corners (1:1)
		drawVoidscapeSlice(asset, master, 0, 0, c, c, x, y, c, c);
		drawVoidscapeSlice(asset, master, mw - c, 0, c, c, x + w - c, y, c, c);
		drawVoidscapeSlice(asset, master, 0, mh - c, c, c, x, y + h - c, c, c);
		drawVoidscapeSlice(asset, master, mw - c, mh - c, c, c, x + w - c, y + h - c, c, c);
		// Top / bottom rails (stretched horizontally, optional 1:1 center ornament)
		drawVoidscapeSliceRailH(asset, master, c, 0, mw - c * 2, c,
			x + c, y, w - c * 2, c, topCenterW);
		drawVoidscapeSliceRailH(asset, master, c, mh - c, mw - c * 2, c,
			x + c, y + h - c, w - c * 2, c, bottomCenterW);
		// Left / right rails (stretched vertically)
		drawVoidscapeSlice(asset, master, 0, c, c, mh - c * 2, x, y + c, c, h - c * 2);
		drawVoidscapeSlice(asset, master, mw - c, c, c, mh - c * 2, x + w - c, y + c, c, h - c * 2);
	}

	// Three-slice horizontal bar (title plates, section headers): end caps 1:1, middle stretched,
	// optional 1:1 center ornament. Master art is exported at the bar's on-screen height.
	private void drawVoidscapeThreeSliceH(String asset, int x, int y, int w, int h, int cap, int centerW) {
		Sprite master = getVoidscapeSkinSprite(asset);
		if (master == null) {
			return;
		}
		int mw = master.getWidth();
		int mh = master.getHeight();
		int c = Math.min(cap, Math.min(mw / 2 - 1, w / 2 - 1));
		if (c <= 0) {
			drawVoidscapeSkinSprite(asset, x, y, w, h);
			return;
		}
		drawVoidscapeSlice(asset, master, 0, 0, c, mh, x, y, c, h);
		drawVoidscapeSlice(asset, master, mw - c, 0, c, mh, x + w - c, y, c, h);
		drawVoidscapeSliceRailH(asset, master, c, 0, mw - c * 2, mh, x + c, y, w - c * 2, h, centerW);
	}

	private void drawVoidscapeHudSkin() {
		if (!useVoidscapeHudSkin()) {
			return;
		}
		refreshVoidscapeCurrentAccountCache();
		if (!isShowDialogBank() && !isVoidscapeRiftTeleportMenu()) {
			drawVoidscapeLocationPlaque(); // plaque stays hidden while banking (per design)
		}
		if (!voidscapeUseMobilePanelShell()) {
			// The small-HUD preset gives the freed rows to the bank panel; tab clicks are
			// already ignored while banking (handleVoidscapeHudSkinTabClick early-out).
			if (!(isShowDialogBank() && voidscapeClassicWebSmallHud())) {
				drawVoidscapeTopTabs();
			}
		}
	}

	private int voidscapeIconTabsSpan() {
		int gap = voidscapeTopTabGap();
		return (voidscapeTopTabSize() * VOIDSCAPE_TOP_TAB_COUNT)
			+ (gap * (VOIDSCAPE_TOP_TAB_COUNT - 1));
	}

	private int voidscapeTopTabsSpan() {
		return voidscapeIconTabsSpan();
	}

	private int voidscapeTopTabsStartX() {
		return this.getSurface().width2 - voidscapeIconTabsSpan() - 3;
	}

	private int voidscapePanelSizeClass() {
		int width = this.getGameWidth();
		if (width <= 680) return 0;
		if (width <= 760) return 1;
		if (width <= 860) return 2;
		if (width <= 960) return 3;
		return 4;
	}

	// Compact chrome at the smallest native viewport presets, so the
	// HUD has to give as much screen as possible back to the world there.
	private boolean voidscapeCompactHud() {
		return voidscapePanelSizeClass() == 0;
	}

	private boolean voidscapeClassicWebSmallHud() {
		return useVoidscapeHudSkin() && !isAndroid()
			&& this.getGameWidth() <= 560 && this.getGameHeight() <= 380;
	}

	private boolean isVoidscapeRiftTeleportMenu() {
		if (!this.optionsMenuShow || this.optionsMenuCount != 5) {
			return false;
		}
		int destinationCount = 0;
		destinationCount += hasVoidscapeOption("Void Enclave") ? 1 : 0;
		destinationCount += hasVoidscapeOption("Edgeville") ? 1 : 0;
		destinationCount += hasVoidscapeOption("Varrock") ? 1 : 0;
		destinationCount += hasVoidscapeOption("Falador") ? 1 : 0;
		destinationCount += hasVoidscapeOption("Ardougne") ? 1 : 0;
		return destinationCount == 5 || destinationCount == 4 && hasVoidscapeOption("Stay here");
	}

	private boolean hasVoidscapeOption(String optionText) {
		for (int i = 0; i < this.optionsMenuCount && i < this.optionsMenuText.length; i++) {
			if (optionText.equals(this.optionsMenuText[i])) {
				return true;
			}
		}
		return false;
	}

	private boolean voidscapeUseCompactStatsPanel() {
		return voidscapeClassicWebSmallHud() || (useVoidscapeHudSkin() && isAndroid());
	}

	private boolean voidscapeAccountSwitcherEnabled() {
		return false;
	}

	public boolean isVoidscapeClassicWebSmallHud() {
		return voidscapeClassicWebSmallHud();
	}

	public int getVoidscapeDesktopOverlayTopSafeY() {
		if (!voidscapeClassicWebSmallHud()) {
			return 0;
		}
		return VOIDSCAPE_TOP_TAB_Y + voidscapeTopTabSize() + 5;
	}

	public int getVoidscapeDesktopOverlayBottomSafeY() {
		if (!voidscapeClassicWebSmallHud()) {
			return getGameHeight();
		}
		return Math.max(getVoidscapeDesktopOverlayTopSafeY() + 24, voidscapeChatTabTop() - 4);
	}

	private int voidscapeTopTabSize() {
		if (voidscapeClassicWebSmallHud()) {
			return 44;
		}
		if (voidscapeUseNativeAndroidCompactTopTabs()) {
			return 44;
		}
		switch (voidscapePanelSizeClass()) {
			case 0:
				return 52;
			case 1:
				return 54;
			case 2:
				return 56;
			case 3:
				return 58;
			default:
				return 60;
		}
	}

	private boolean voidscapeUseNativeAndroidCompactTopTabs() {
		return isNativeAndroidClient() && this.getGameWidth() <= this.getGameHeight();
	}

	private int voidscapeTopTabGap() {
		return voidscapeCompactHud() ? 1 : 2;
	}

	private int voidscapeTopTabIconSize() {
		int cell = voidscapeTopTabSize();
		if (voidscapeClassicWebSmallHud()) {
			return Math.max(30, cell - 8);
		}
		if (cell >= 58) {
			return 48;
		}
		if (cell >= 54) {
			return 46;
		}
		if (cell >= 50) {
			return 44;
		}
		return 40;
	}

