	private void drawVoidscapeCornerLogoutButton() {
		int x = voidscapeAccountButtonX();
		int y = voidscapeAccountButtonY();
		int width = voidscapeAccountButtonWidth();
		int height = voidscapeAccountButtonHeight();
		boolean active = mouseOverVoidscapeCornerLogoutButton();
		int fill = active ? 0xB81E2D : 0x8F1522;
		int inner = active ? 0xE33A45 : 0xB52530;
		this.getSurface().drawBoxAlpha(x, y, width, height, 0x14090B, 210);
		this.getSurface().drawBoxAlpha(x + 2, y + 2, Math.max(1, width - 4), Math.max(1, height - 4), fill, 232);
		this.getSurface().drawBoxBorder(x, width, y, height, active ? 0xFFE7B0 : 0xFFB6A0);
		this.getSurface().drawBoxBorder(x + 2, Math.max(1, width - 4), y + 2, Math.max(1, height - 4), inner);
		this.getSurface().drawLineHoriz(x + 5, y + 5, Math.max(1, width - 10), 0xFF7580);
		this.getSurface().drawColoredStringCentered(x + width / 2, "Logout", 0xFFFFFF, 0, 0,
			y + height / 2 + 4);
	}

	private void drawVoidscapeAccountDrawerCue(int x, int y, int width, int height) {
		boolean collapsed = this.voidscapeAccountDrawerCollapsed && !this.voidscapeAccountMenuOpen
			&& !this.voidscapeAccountAddFormOpen;
		int cueW = voidscapeCompactHud() ? 9 : 10;
		int cueH = voidscapeCompactHud() ? 13 : 15;
		int cx = collapsed ? x + 7 : x + width - 9;
		int cy = y + height / 2;
		this.getSurface().drawBoxAlpha(cx - cueW / 2 - 2, cy - cueH / 2 - 1,
			cueW + 4, cueH + 2, 0x120B16, 170);
		for (int row = 0; row < cueH; row++) {
			int half = Math.abs(row - cueH / 2);
			int lineW = cueW - half;
			if (lineW <= 0) {
				continue;
			}
			int startX = collapsed ? cx - cueW / 2 : cx - cueW / 2 + half;
			this.getSurface().drawLineHoriz(startX, cy - cueH / 2 + row, lineW, 0xD9B24D);
		}
	}

	private void drawVoidscapeAccountMenu() {
		if (!voidscapeAccountSwitcherEnabled()) {
			this.voidscapeAccountMenuOpen = false;
			this.voidscapeAccountAddFormOpen = false;
			this.voidscapeAccountDrawerCollapsed = false;
			return;
		}
		if (!this.voidscapeAccountMenuOpen) {
			return;
		}
		ensureVoidscapeSavedAccountsLoaded();
		int x = voidscapeAccountPanelX();
		int y = voidscapeAccountPanelY();
		int width = voidscapeAccountPanelWidth();
		int height = voidscapeAccountPanelHeight();
		if (this.voidscapeAccountAddFormOpen) {
			drawVoidscapeAccountAddForm(x, y, width, height);
			return;
		}
		drawVoidscapeAccountPanelShell(x, y, width, height, "ACCOUNT");

		int rowX = x + (voidscapeCompactHud() ? 12 : 14);
		int rowW = width - (voidscapeCompactHud() ? 24 : 28);
		int rowH = voidscapeAccountRowHeight();
		int rowGap = voidscapeAccountRowGap();
		int rowY = y + voidscapeAccountHeaderHeight();
		int rows = voidscapeVisibleAccountCount();
		for (int i = 0; i < rows; i++) {
			drawVoidscapeAccountRow(this.voidscapeSavedAccounts.get(i), rowX, rowY + i * (rowH + rowGap), rowW, rowH, i);
		}
		if (rows < VOIDSCAPE_ACCOUNT_MAX) {
			drawVoidscapeAddAccountRow(rowX, rowY + rows * (rowH + rowGap), rowW, rowH);
		}
	}

	private void drawVoidscapeAccountPanelShell(int x, int y, int width, int height, String title) {
		int headerH = voidscapeAccountHeaderHeight();
		this.getSurface().drawBoxAlpha(x, y, width, height, 0x050308, 58);
		this.getSurface().drawBoxAlpha(x + 1, y + 1, width - 2, headerH - 1, 0x0D0914, 222);
		this.getSurface().drawBoxAlpha(x + 1, y + headerH, width - 2, height - headerH - 1, 0x0B0810,
			voidscapeStructuredPanelBodyAlpha());
		this.getSurface().drawLineHoriz(x, y, width, UiSkin.GOLD_BEVEL);
		this.getSurface().drawLineHoriz(x, y + height - 1, width, UiSkin.SHADOW_A);
		this.getSurface().drawLineVert(x, y, UiSkin.GOLD_BEVEL, height);
		this.getSurface().drawLineVert(x + width - 1, y, UiSkin.SHADOW_A, height);
		this.getSurface().drawLineHoriz(x + 2, y + headerH - 1, width - 4, 0x6E5737);
		this.getSurface().drawLineHoriz(x + 2, y + headerH, width - 4, 0x18111E);
		this.getSurface().drawBoxBorder(x + 2, width - 4, y + 2, height - 4, 0x271F2D);
		this.getSurface().drawColoredStringCentered(x + width / 2, title, 0xF0DFA3, 0, 4,
			y + (voidscapeCompactHud() ? 24 : 28));
	}

	private void drawVoidscapeAccountRow(VoidscapeSavedAccount account, int x, int y, int width, int height, int index) {
		boolean current = isCurrentVoidscapeAccount(account);
		boolean hover = !current && this.mouseX >= x && this.mouseX < x + width
			&& this.mouseY >= y && this.mouseY < y + height;
		int rowColor = current ? 0x1E1627 : hover ? 0x241633 : 0x0C0911;
		int rowAlpha = current ? 188 : hover ? 180 : 134;
		int borderColor = current ? 0x8C6F3D : hover ? 0x6A4FA0 : 0x2F2434;
		this.getSurface().drawBoxAlpha(x, y, width, height, rowColor, rowAlpha);
		this.getSurface().drawBoxBorder(x, width, y, height, borderColor);
		this.getSurface().drawLineHoriz(x + 2, y + 1, width - 4, current ? 0xB8914F : 0x3A2A44);
		int icon = voidscapeCompactHud() ? 28 : 36;
		int iconX = x + (voidscapeCompactHud() ? 12 : 16);
		int iconY = y + (height - icon) / 2;
		drawVoidscapeSkinSprite(current ? "account-avatar.png" : "account-avatar-muted.png", iconX, iconY, icon, icon);
		int textX = iconX + icon + (voidscapeCompactHud() ? 10 : 14);
		int arrow = voidscapeCompactHud() ? 26 : 32;
		int arrowX = x + width - arrow - (voidscapeCompactHud() ? 10 : 13);
		int removeSize = voidscapeAccountRemoveButtonSize();
		int removeX = voidscapeAccountRemoveButtonX(x, width);
		int actionX = removeX;
		int nameW = Math.max(20, actionX - textX - 8);
		String name = fitVoidscapeText(voidscapeAccountDisplayName(account), nameW, 4);
		int nameColor = current ? 0xF0DFA3 : 0xFFFFFF;
		this.getSurface().drawString(name, textX, y + (voidscapeCompactHud() ? 18 : 22), nameColor, 4);
		String combat = account.combatLevel > 0 ? "Combat: " + account.combatLevel : "Combat: ?";
		this.getSurface().drawString(fitVoidscapeText(combat, nameW, 1), textX,
			y + (voidscapeCompactHud() ? 32 : 40), 0xC9BFA6, 1);
		if (usesSecureCredentialStore() || !current) {
			drawVoidscapeAccountRemoveButton(removeX, y + (height - removeSize) / 2, removeSize);
		}
		if (!current) {
			drawVoidscapeSkinSprite("account-switch-arrow.png", arrowX, y + (height - arrow) / 2, arrow, arrow);
		}
	}

	private int voidscapeAccountRemoveButtonSize() {
		return voidscapeCompactHud() ? 18 : 20;
	}

	private int voidscapeAccountRemoveButtonX(int rowX, int rowWidth) {
		int arrow = voidscapeCompactHud() ? 26 : 32;
		int arrowX = rowX + rowWidth - arrow - (voidscapeCompactHud() ? 10 : 13);
		return arrowX - voidscapeAccountRemoveButtonSize() - (voidscapeCompactHud() ? 6 : 8);
	}

	private boolean mouseOverVoidscapeAccountRemove(int rowX, int rowY, int rowW, int rowH) {
		int size = voidscapeAccountRemoveButtonSize();
		int x = voidscapeAccountRemoveButtonX(rowX, rowW);
		int y = rowY + (rowH - size) / 2;
		return this.mouseX >= x && this.mouseX <= x + size
			&& this.mouseY >= y && this.mouseY <= y + size;
	}

