	public void captureScreenshot() {
		String result = this.clientPort == null ? "" : this.clientPort.saveScreenshot();
		if (result == null || result.length() == 0) {
			showMessage(false, null, "Screenshots are not supported by this client.",
				MessageType.GAME, 0, null);
			return;
		}
		if (result.startsWith("ERROR:")) {
			showMessage(false, null, "Screenshot failed: " + result.substring("ERROR:".length()),
				MessageType.GAME, 0, null);
			return;
		}
		showMessage(false, null, "Screenshot saved: " + result, MessageType.GAME, 0, null);
	}

	private void changeRenderingScalar(Boolean scaleUp) {
		windowScaleMode = false;
		scalarChangedSinceLogin = true;

		final List<Float> scalars = scalingType == ScalingAlgorithm.INTEGER_SCALING ? integerScalars : interpolationScalars;
		if (scalars == null || scalars.isEmpty()) {
			return;
		}

		int idx = scalarIndexForStep(renderingScalar, scalars, scaleUp);
		newRenderingScalar = scalars.get(idx);

		saveScalingSettings(scalingType, newRenderingScalar);
	}

	private int scalarIndexForStep(float scalar, List<Float> scalars, boolean scaleUp) {
		if (scaleUp) {
			for (int i = 0; i < scalars.size(); i++) {
				if (scalars.get(i) > scalar + 0.001f) {
					return i;
				}
			}
			return scalars.size() - 1;
		}

		for (int i = scalars.size() - 1; i >= 0; i--) {
			if (scalars.get(i) < scalar - 0.001f) {
				return i;
			}
		}
		return 0;
	}

	private void enableWindowScaleMode() {
		windowScaleMode = true;
		removeClientSetting("scaling_scalar");
		ScaledWindow.getInstance().applyViewportPreset(ScaledWindow.getViewportPresetIndex());
	}

	void cycleScalingType() {
		if (scalingType == ScalingAlgorithm.INTEGER_SCALING) {
			scalingType = ScalingAlgorithm.BILINEAR_INTERPOLATION;
		} else if (scalingType == ScalingAlgorithm.BILINEAR_INTERPOLATION) {
			scalingType = ScalingAlgorithm.BICUBIC_INTERPOLATION;
		} else {
			scalingType = ScalingAlgorithm.INTEGER_SCALING;

			// When going back to integer scaling, round the scalar if needed
			if (renderingScalar != (int) renderingScalar) {
				newRenderingScalar = (int) renderingScalar;
			}
		}

		if (windowScaleMode) {
			saveClientSetting("scaling_type", String.valueOf(scalingType.ordinal()));
		} else {
			saveScalingSettings(scalingType, newRenderingScalar);
		}
	}

