	public final void showMessage(boolean crownEnabled, String sender, String message, MessageType type, int crownID,
								  String formerName, String colourOverride, String displaySender) {
		try {

			if ((type == MessageType.PRIVATE_RECIEVE || type == MessageType.CHAT || type == MessageType.TRADE
				|| type == MessageType.GLOBAL_CHAT || type == MessageType.CLAN_CHAT) && formerName != null && !crownEnabled) {
				String clanKey = StringUtil.displayNameToKey(formerName);
				if (null == clanKey) {
					return;
				}

				for (int i = 0; i < SocialLists.ignoreListCount; ++i) {
					if (clanKey.equals(StringUtil.displayNameToKey(SocialLists.ignoreList[i]))) {
						return;
					}
				}
			}

			String colour = null != colourOverride ? colourOverride : type.color;
			String formattedSender = displaySender != null ? displaySender : sender;

			if (!crownEnabled)
				crownID = 0;

			if (this.messageTabSelected != MessageTab.ALL) {
				if (((type == MessageType.FRIEND_STATUS || type == MessageType.PRIVATE_RECIEVE
					|| type == MessageType.PRIVATE_SEND) && this.messageTabSelected != MessageTab.PRIVATE)
					|| type == MessageType.GLOBAL_CHAT && this.messageTabSelected != MessageTab.PRIVATE) {
					this.messageTabActivity_Private = 200;
				}

				if (type == MessageType.CHAT && this.messageTabSelected != MessageTab.CHAT) {
					this.messageTabActivity_Chat = 200;
				}

				if (type == MessageType.QUEST && this.messageTabSelected != MessageTab.QUEST) {
					this.messageTabActivity_Quest = 200;
				}

				if (type == MessageType.GLOBAL_CHAT && this.messageTabSelected != MessageTab.GLOBAL) {
					this.messageTabActivity_Global = 200;
				}

				if (type == MessageType.GAME || type == MessageType.INVENTORY) {
					this.messageTabActivity_Game = 200;
				}

				if (C_MESSAGE_TAB_SWITCH) {
					if (type == MessageType.GAME && this.messageTabSelected != MessageTab.ALL) {
						this.messageTabSelected = MessageTab.ALL;
					}

					if ((type == MessageType.FRIEND_STATUS || type == MessageType.PRIVATE_RECIEVE
						|| type == MessageType.PRIVATE_SEND) && this.messageTabSelected != MessageTab.PRIVATE
						&& this.messageTabSelected != MessageTab.ALL) {
						this.messageTabSelected = MessageTab.ALL;
					}
				}
			}

			for (int i = 99; i > 0; --i) {
				MessageHistory.messageHistoryType[i] = MessageHistory.messageHistoryType[i - 1];
				MessageHistory.messageHistoryTimeout[i] = MessageHistory.messageHistoryTimeout[i - 1];
				MessageHistory.messageHistoryCrownID[i] = MessageHistory.messageHistoryCrownID[i - 1];
				MessageHistory.messageHistorySender[i] = MessageHistory.messageHistorySender[i - 1];
				MessageHistory.messageHistoryClan[i] = MessageHistory.messageHistoryClan[i - 1];
				MessageHistory.messageHistoryMessage[i] = MessageHistory.messageHistoryMessage[i - 1];
				MessageHistory.messageHistoryColor[i] = MessageHistory.messageHistoryColor[i - 1];
			}
			MessageHistory.messageHistoryType[0] = type;
			MessageHistory.messageHistoryTimeout[0] = 300;
			MessageHistory.messageHistorySender[0] = formattedSender;
			MessageHistory.messageHistoryCrownID[0] = crownID;
			MessageHistory.messageHistoryClan[0] = formerName;
			MessageHistory.messageHistoryMessage[0] = message;
			MessageHistory.messageHistoryColor[0] = colour;
			String msg = colour + StringUtil.formatMessage(message, formattedSender, type, colour);

			if (type == MessageType.CHAT) {
				this.voidscapeAddWrapped(msg, this.panelMessageTabs.controlScrollAmount[this.panelMessageChat] == this.panelMessageTabs.controlListCurrentSize[this.panelMessageChat]
					- 4, crownID, sender, formerName, this.panelMessageChat);
			}

			if (type == MessageType.QUEST) {
				this.voidscapeAddWrapped(msg, this.panelMessageTabs.controlScrollAmount[this.panelMessageQuest] == this.panelMessageTabs.controlListCurrentSize[this.panelMessageQuest]
						- 4, 0, null, null,
					this.panelMessageQuest);
			}
			if (type == MessageType.GLOBAL_CHAT) {
				this.voidscapeAddWrapped(msg, this.panelMessageTabs.controlScrollAmount[this.panelMessagePrivate] == this.panelMessageTabs.controlListCurrentSize[this.panelMessagePrivate]
					- 4, crownID, sender, formerName, this.panelMessagePrivate);
				// Additive: the dedicated Global history list (voidscape-skin
				// sixth tab). Global chat keeps landing everywhere it did
				// before — MessageHistory (All tab) and the Private list.
				this.voidscapeAddWrapped(msg, this.panelMessageTabs.controlScrollAmount[this.panelMessageGlobal] == this.panelMessageTabs.controlListCurrentSize[this.panelMessageGlobal]
					- 4, crownID, sender, formerName, this.panelMessageGlobal);
			}
			// CLAN_CHAT (wire type 9) intentionally has no dedicated tab any more:
			// it still lands in MessageHistory above, so it shows on the All tab.

			if (type == MessageType.PRIVATE_RECIEVE || type == MessageType.PRIVATE_SEND) {
				int crown = crownID;
				if (type != MessageType.PRIVATE_RECIEVE) {
					crown = 0;
				}

				this.voidscapeAddWrapped(msg, this.panelMessageTabs.controlListCurrentSize[this.panelMessagePrivate]
					- 4 == this.panelMessageTabs.controlScrollAmount[this.panelMessagePrivate], crown, sender, formerName, this.panelMessagePrivate);
			}

			logChat(sender, message, type);

		} catch (RuntimeException var12) {
			throw GenUtil.makeThrowable(var12, "client.BD(" + crownEnabled + ',' + (sender != null ? "{...}" : "null")
				+ ',' + "dummy" + ',' + (message != null ? "{...}" : "null") + ',' + type + ',' + crownID + ','
				+ (formerName != null ? "{...}" : "null") + ',' + ')');
		}
	}

	private void logChat(String sender, String message, MessageType type) {
		/* TODO: Apparently ANSI colors don't work by default on Windows machines, which is seemingly
		    what the majority of players use.
		    I will leave the functionality here for now, but it should be looked into if there is a way to
		    enable them programmatically. */
		final String ANSI_RESET = "\u001B[0m";
		final String ANSI_BLACK = "\u001B[30m";
		final String ANSI_RED = "\u001B[31m";
		final String ANSI_GREEN = "\u001B[32m";
		final String ANSI_YELLOW = "\u001B[33m";
		final String ANSI_BLUE = "\u001B[34m";
		final String ANSI_PURPLE = "\u001B[35m";
		final String ANSI_CYAN = "\u001B[36m";
		final String ANSI_WHITE = "\u001B[37m";

		final DateTimeFormatter dateTimeFormatter = DateTimeFormatter.ofPattern("HH:mm:ss");
		final LocalDateTime now = LocalDateTime.now();
		final String currentTime = dateTimeFormatter.format(now);

		// Strip all the freaking color codes
		Pattern pattern = Pattern.compile("[@][A-Za-z][A-Za-z][A-Za-z0-9][@]");
		Matcher matcher = pattern.matcher(message);
		if (matcher.find()) {
			message = matcher.replaceAll("");
		}
		if (sender != null) {
			matcher = pattern.matcher(sender);
			if (matcher.find()) {
				sender = matcher.replaceAll("");
			}
		}


		// Pick a color
		String color = null;
		switch (type.color) {
			case "@yel@":
				color = ANSI_YELLOW;
				break;
			case "@whi@":
				color = ANSI_WHITE;
				break;
			case "@cya@":
				color = ANSI_CYAN;
				break;
			default:
				color = ANSI_RESET;
				break;
		}

		// Handle global going to quest
		if (type == MessageType.QUEST && message.contains("Global$")) {
			color = ANSI_CYAN;
		}

		// Handle NPC dialog
		if (type == MessageType.QUEST && sender != null) {
			color = ANSI_YELLOW;
		}

		if (sender == null || sender.equals("null")) {
			System.out.println("[" + currentTime + "] [" + type.name() + "] " + message);
		} else {
			System.out.println("[" + currentTime + "] [" + type.name() + "] " + sender + ": " + message);
		}
	}

	public boolean hasScroll(MessageTab messageTab) {
		switch(messageTab) {
			case CHAT:
				return this.panelMessageTabs.controlListCurrentSize[this.panelMessageChat] > 4;
			case QUEST:
				return this.panelMessageTabs.controlListCurrentSize[this.panelMessageQuest] > 4;
			case GLOBAL:
				return this.panelMessageTabs.controlListCurrentSize[this.panelMessageGlobal] > 4;
			case PRIVATE:
				return this.panelMessageTabs.controlListCurrentSize[this.panelMessagePrivate] > 4;
			default:
				return false;
		}
	}

	public final void sortOnlineFriendsList() {
		try {

			boolean loopModified = true;

			while (loopModified) {
				loopModified = false;
				for (int i = 0; i < SocialLists.friendListCount - 1; ++i) {
					// If we aren't online and the next is cycle down.
					if ((SocialLists.friendListOnlineStatus[i] & 2) == 0 && (SocialLists.friendListOnlineStatus[i + 1] & 2) != 0
						|| (4 & SocialLists.friendListOnlineStatus[i]) == 0 && (SocialLists.friendListOnlineStatus[1 + i] & 4) != 0) {
						String tmpS = SocialLists.friendListWorld[i];
						SocialLists.friendListWorld[i] = SocialLists.friendListWorld[i + 1];
						SocialLists.friendListWorld[i + 1] = tmpS;

						tmpS = SocialLists.friendList[i];
						SocialLists.friendList[i] = SocialLists.friendList[1 + i];
						SocialLists.friendList[i + 1] = tmpS;

						tmpS = SocialLists.friendListOld[i];
						SocialLists.friendListOld[i] = SocialLists.friendListOld[i + 1];
						SocialLists.friendListOld[i + 1] = tmpS;

						int tmpInt = SocialLists.friendListOnlineStatus[i];
						SocialLists.friendListOnlineStatus[i] = SocialLists.friendListOnlineStatus[i + 1];
						SocialLists.friendListOnlineStatus[i + 1] = tmpInt;

						loopModified = true;
					}
				}
			}

		} catch (RuntimeException var7) {
			throw GenUtil.makeThrowable(var7, "client.RC(" + "dummy" + ')');
		}
	}

	private void startGame(byte var1) {
		try {
			this.fetchContainerSize();
			if (!clientPort.drawLoading(2)) {
				this.errorLoadingData = true;
			} else {
				RSBufferUtils.setStringEncryptor(RSBufferUtils.encryption);
				this.setExperienceArray();
				MiscFunctions.maxReadTries = 1000;
				// We must fetch the server config before continuing.
				String ip;
				int port;
				if ((Config.SERVER_IP != null)) {
					ip = Config.SERVER_IP; // allows override if manually set in Config code
					port = Config.SERVER_PORT; // allows override if manually set in Config code
				} else {
					ip = ClientPort.loadIP(); // loads based on Cache/ip.txt
					port = ClientPort.loadPort(); // loads based on Cache/port.txt
				}
				System.out.println(" ");
				System.out.println(" ");
				System.out.println("Fetching server configs from " + ip + ":" + port);
				System.out.println(" ");
				System.out.println(" ");
				clientPort.showLoadingProgress(5, "Connecting to " + ip + ":" + port);
				try {
					this.getServerConfig();
				} catch (RuntimeException configError) {
					configError.printStackTrace();
					this.errorLoadingData = true;
					clientPort.showLoadingProgress(0, "Unable to connect to server");
					clientPort.drawLoadingError();
				}
			}
		} catch (RuntimeException var9) {
			throw GenUtil.makeThrowable(var9, "client.KC(" + var1 + ')');
		}
	}

