	private void walkToArea(int startX, int startZ, int x1, int z1, int x2, int z2, boolean reachBorder,
							boolean walkToEntity) {
		try {
			if (this.voidScoutActive) {
				showVoidScoutClickBlocked();
				return;
			}

			int count = this.world.findPath(this.pathX, this.pathZ, startX, startZ, x1, x2, z1, z2, reachBorder);
			if (count == -1) {
				if (!walkToEntity) {
					return;
				}

				count = 1;
				this.pathX[0] = x1;
				this.pathZ[0] = z1;
			}

			int pendingMarkerLocalX = this.pathX[0];
			int pendingMarkerLocalZ = this.pathZ[0];
			--count;
			startZ = this.pathZ[count];
			startX = this.pathX[count];
			--count;
			if (!walkToEntity) {
				this.packetHandler.getClientStream().newPacket(187);
			} else {
				this.packetHandler.getClientStream().newPacket(16);
			}

			this.packetHandler.getClientStream().bufferBits.putShort(this.midRegionBaseX + startX);
			this.packetHandler.getClientStream().bufferBits.putShort(this.midRegionBaseZ + startZ);

			//System.out.println("walkToArea, startX: " + (this.midRegionBaseX + startX) + " (" + this.midRegionBaseX + " + " + startX + ")");
			//System.out.println("walkToArea, startZ: " + (this.midRegionBaseZ + startZ) + " (" + this.midRegionBaseZ + " + " + startZ + ")");

			if (walkToEntity && count == -1 && (startX + this.midRegionBaseX) % 5 == 0) {
				count = 0;
			}

			for (int i = count; i >= 0 && i > count - 25; --i) {
				this.packetHandler.getClientStream().bufferBits.putByte(this.pathX[i] - startX);
				this.packetHandler.getClientStream().bufferBits.putByte(this.pathZ[i] - startZ);

				//System.out.println("walkToArea, count: " + count + ", pathX[" + i + "]: " + (this.pathX[i] - startX) + " (" + this.pathX[i] + " - " + startX + ")");
				//System.out.println("walkToArea, count: " + count + ", pathZ[" + i + "]: " + (this.pathZ[i] - startZ) + " (" + this.pathZ[i] + " - " + startZ + ")");
			}

			this.packetHandler.getClientStream().finishPacket();
			this.mouseWalkY = this.mouseY;
			this.mouseWalkX = this.mouseX;
			this.mouseClickXStep = -24;
			beginPendingInputFeedback(pendingMarkerLocalX, pendingMarkerLocalZ);
		} catch (RuntimeException var13) {
			throw GenUtil.makeThrowable(var13, "client.DD(" + x1 + ',' + walkToEntity + ',' + startX + ',' + z1 + ',' + startZ
				+ ',' + x2 + ',' + reachBorder + ',' + z2 + ',' + "dummy" + ')');
		}
	}

	private void beginPendingInputFeedback(int localX, int localZ) {
		if (!optionPendingInputMarker) {
			clearPendingInputMarker();
			return;
		}

		if (this.localPlayer == null || localX < 0 || localZ < 0 || localX >= 95 || localZ >= 95) {
			clearPendingInputMarker();
			return;
		}

		this.pendingInputMarkerActive = true;
		this.pendingInputMarkerLocalX = localX;
		this.pendingInputMarkerLocalZ = localZ;
		this.pendingInputMarkerStartMillis = System.currentTimeMillis();
	}

	private void clearPendingInputMarker() {
		this.pendingInputMarkerActive = false;
		this.pendingInputMarkerLocalX = -1;
		this.pendingInputMarkerLocalZ = -1;
		this.pendingInputMarkerStartMillis = 0L;
	}

	private int localPlayerTileX() {
		return (this.localPlayer.currentX - 64) / this.tileSize;
	}

	private int localPlayerTileZ() {
		return (this.localPlayer.currentZ - 64) / this.tileSize;
	}

	private int nextRemoteEntityMovePixels() {
		long nowNs = System.nanoTime();
		if (this.remoteEntityMoveLastNs == 0L) {
			this.remoteEntityMoveLastNs = nowNs;
			return Config.C_MOVE_PER_FRAME;
		}

		double elapsedMillis = (nowNs - this.remoteEntityMoveLastNs) / 1000000.0D;
		this.remoteEntityMoveLastNs = nowNs;
		elapsedMillis = Math.max(0.0D, Math.min(REMOTE_ENTITY_MOVEMENT_MAX_ELAPSED_MILLIS, elapsedMillis));
		double movePixels = this.remoteEntityMoveCarryPixels
			+ Config.C_MOVE_PER_FRAME * elapsedMillis / REMOTE_ENTITY_MOVEMENT_FRAME_MILLIS;
		int wholePixels = (int) movePixels;
		this.remoteEntityMoveCarryPixels = movePixels - wholePixels;
		return wholePixels;
	}

	/**
	 * voidscape — world-map auto-walker. Send a destination (absolute world
	 * coords; floor encoded as Y / 944) to the server. Server pathfinds and
	 * drives walking; the route comes back via SEND_WORLD_WALK_ROUTE (opcode
	 * 100) and is stored in {@code worldWalkRouteX/Y} for the slice-5 UI.
	 */
	public void sendWorldWalkRequest(int destX, int destY) {
		this.webWorldWalkLastRequestX = destX;
		this.webWorldWalkLastRequestY = destY;
		this.webWorldWalkLastRequestAtMillis = System.currentTimeMillis();
		this.packetHandler.getClientStream().newPacket(orsc.net.Opcodes.Out.WORLD_WALK_REQUEST.getOpcode());
		this.packetHandler.getClientStream().bufferBits.putShort(destX);
		this.packetHandler.getClientStream().bufferBits.putShort(destY);
		this.packetHandler.getClientStream().finishPacket();
	}

	/** Receiver for SEND_WORLD_WALK_ROUTE; called from PacketHandler. */
	public void setWorldWalkRoute(boolean ok, int reason, int[] xs, int[] ys) {
		this.worldWalkRouteOk = ok;
		this.worldWalkRouteReason = reason;
		this.worldWalkRouteX = xs;
		this.worldWalkRouteY = ys;
		this.webWorldWalkLastRouteAtMillis = System.currentTimeMillis();
		this.webWorldWalkLastRouteOk = ok;
		this.webWorldWalkLastRouteReason = reason;
		this.webWorldWalkLastRouteCount = xs == null || ys == null ? 0 : Math.min(xs.length, ys.length);
		if (this.voidScoutActive) {
			if (ok) {
				return;
			}
			this.voidScoutNudgePending = false;
		}
		String msg;
		if (ok) {
			msg = "@gre@World-walk: @whi@" + xs.length + " tiles.";
		} else {
			// Reason codes mirror WorldWalkRequest.REASON_* (server side).
			switch (reason) {
				case 1: msg = "@red@Can't find a path there."; break;
				case 2: msg = "@red@Too far to plot a route from here."; break;
				case 3: msg = "@red@Invalid destination."; break;
				case 4: return;  // SAME_TILE — already there, stay silent.
				case 5: msg = "@red@Can't reach that floor from here."; break;
				case 6: msg = "@red@Finish what you're doing first."; break;
				case 7: msg = "@red@Can't world-walk during combat."; break;
				default: msg = "@red@World-walk failed.";
			}
		}
		this.showMessage(false, null, msg, MessageType.GAME, 0, null);
	}

	/** Receiver for SEND_VOID_SCOUT_STATE; called from PacketHandler. */
	public void setVoidScoutState(boolean active, int bodyX, int bodyY, int viewX, int viewY, int maxDistance, int remainingMillis) {
		final boolean wasActive = this.voidScoutActive;
		final boolean viewChanged = this.voidScoutViewX != viewX || this.voidScoutViewY != viewY;
		this.voidScoutActive = active;
		this.voidScoutBodyX = bodyX;
		this.voidScoutBodyY = bodyY;
		this.voidScoutViewX = viewX;
		this.voidScoutViewY = viewY;
		this.voidScoutMaxDistance = maxDistance;
		this.voidScoutExpiresAtMillis = active && remainingMillis > 0
			? System.currentTimeMillis() + remainingMillis
			: 0L;
		if (active && !wasActive && this.localPlayer != null) {
			this.voidScoutBodyDirection = this.localPlayer.direction;
		}
		this.voidScoutLastNudgeMillis = 0L;
		if (viewChanged) {
			this.voidScoutNudgePending = false;
		}
		if (!active) {
			this.voidScoutBodySpriteIndex = -1;
			this.voidScoutBodyPreviousPlayer = null;
			this.voidScoutNudgePending = false;
			this.voidScoutExpiresAtMillis = 0L;
		}
		this.mouseClickXStep = 0;
		this.topMouseMenuVisible = false;
	}

	private void sendVoidScoutCancel() {
		this.packetHandler.getClientStream().newPacket(orsc.net.Opcodes.Out.VOID_SCOUT_CANCEL.getOpcode());
		this.packetHandler.getClientStream().finishPacket();
	}

	private boolean handleVoidScoutArrowKeys() {
		if (!this.voidScoutActive) return false;

		int screenDx = 0;
		int screenDy = 0;
		if (this.keyLeft && !this.keyRight) screenDx = -1;
		if (this.keyRight && !this.keyLeft) screenDx = 1;
		if (this.keyUp && !this.keyDown) screenDy = -1;
		if (this.keyDown && !this.keyUp) screenDy = 1;

		if (screenDx == 0 && screenDy == 0) return false;

		long now = System.currentTimeMillis();
		if (this.voidScoutNudgePending && now - this.voidScoutNudgePendingMillis < 1500L) {
			return true;
		}
		if (now - this.voidScoutLastNudgeMillis < VOID_SCOUT_NUDGE_INTERVAL_MS) {
			return true;
		}
		this.voidScoutLastNudgeMillis = now;
		this.voidScoutNudgePending = true;
		this.voidScoutNudgePendingMillis = now;

		final int[] step = resolveVoidScoutScreenStep(screenDx, screenDy);
		final int viewX = this.voidScoutViewX > 0 ? this.voidScoutViewX : this.playerLocalX + this.midRegionBaseX;
		final int viewY = this.voidScoutViewY > 0 ? this.voidScoutViewY : this.playerLocalZ + this.midRegionBaseZ;
		this.sendWorldWalkRequest(viewX + step[0] * VOID_SCOUT_KEY_STEP, viewY + step[1] * VOID_SCOUT_KEY_STEP);
		return true;
	}

	private int[] resolveVoidScoutScreenStep(int screenDx, int screenDy) {
		final int fallbackX = screenDx;
		final int fallbackY = screenDy;
		final int localX = this.voidScoutViewX - this.midRegionBaseX;
		final int localZ = this.voidScoutViewY - this.midRegionBaseZ;
		if (localX <= 0 || localZ <= 0 || localX >= 95 || localZ >= 95) {
			return new int[]{fallbackX, fallbackY};
		}

		final int baseSceneX = localX * this.tileSize + 64;
		final int baseSceneZ = localZ * this.tileSize + 64;
		final int[] baseProjection = new int[3];
		if (!projectVoidScoutTileCenter(baseProjection, baseSceneX, baseSceneZ)) {
			return new int[]{fallbackX, fallbackY};
		}

		int bestDx = fallbackX;
		int bestDy = fallbackY;
		int bestScore = Integer.MIN_VALUE;
		for (int tileDx = -1; tileDx <= 1; tileDx++) {
			for (int tileDy = -1; tileDy <= 1; tileDy++) {
				if (tileDx == 0 && tileDy == 0) continue;
				final int candidateLocalX = localX + tileDx;
				final int candidateLocalZ = localZ + tileDy;
				if (candidateLocalX <= 0 || candidateLocalZ <= 0 || candidateLocalX >= 95 || candidateLocalZ >= 95) continue;

				final int[] projection = new int[3];
				final int sceneX = candidateLocalX * this.tileSize + 64;
				final int sceneZ = candidateLocalZ * this.tileSize + 64;
				if (!projectVoidScoutTileCenter(projection, sceneX, sceneZ)) continue;

				final int projectedDx = projection[0] - baseProjection[0];
				final int projectedDy = projection[1] - baseProjection[1];
				final int score = projectedDx * screenDx + projectedDy * screenDy;
				if (score > bestScore) {
					bestScore = score;
					bestDx = tileDx;
					bestDy = tileDy;
				}
			}
		}
		return new int[]{bestDx, bestDy};
	}

	private boolean projectVoidScoutTileCenter(final int[] out, final int sceneX, final int sceneZ) {
		final int sceneY = -this.world.getElevation(sceneX, sceneZ) - 2;
		return this.scene.projectToScreen(sceneX, sceneY, sceneZ, out);
	}

